                            {/* Roster Selection Area */}
                            <div className="flex-1 flex flex-col gap-2 sm:gap-3 bg-stone-950/40 rounded-xl sm:rounded-2xl border border-stone-800 shadow-inner min-h-0 min-w-0 overflow-hidden">
