                                >
                                    <div className="flex items-center gap-2">
                                        {isOngoingManual ? <Play className="w-3 h-3 sm:w-5 animate-pulse text-amber-100" /> : <Gamepad2 className="w-3 h-3 sm:w-5" />}
                                        <span className="text-[10px] sm:text-base font-black uppercase tracking-tight">
                                            {isOngoingManual ? 'Resume Assault' : 'Direct Assault'}
                                        </span>
                                    </div>
                                    <span className="text-[7px] sm:text-[10px] font-bold opacity-60 uppercase tracking-widest">
                                        {isOngoingManual ? 'Continue Exploration' : 'Active Control'}
                                    </span>
                                </button>
                            </div>
                            {!isUnlocked && (
                                <div className="mt-3 text-center">
                                    <span className="text-[8px] sm:text-xs text-red-500 font-bold uppercase tracking-widest flex items-center justify-center gap-1.5">
                                        <Lock className="w-3 h-3" /> Area Exploration Locked
                                    </span>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            {/* Recall Confirmation Modal */}
            <ConfirmationModal 
                isOpen={!!showRecallConfirm}
                title="Recall Squad?"
                message={showRecallConfirm === 'MANUAL' 
                    ? "Abandon the current assault? You will lose all progress on this floor and return the entire squad to the Tavern immediately. No rewards will be gained."
                    : "Cancel strategic deployment? The squad will return to the Tavern immediately. No loot will be collected and energy will not be refunded."
                }
                confirmLabel="Confirm Recall"
                cancelLabel="Stay Deployed"
                isDanger={true}
                onConfirm={handleConfirmRecall}
                onCancel={() => setShowRecallConfirm(null)}
            />
        </div>
    );
};

export default DungeonTab;

import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { ArrowLeft, Heart, Coins, Gift, MessageSquare, UserPlus, Info, Zap, Package, X, ChevronRight, Search, Wrench, LogOut, Star, UserMinus, Ban } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { Mercenary } from '../../../models/Mercenary';
import { CONTRACT_CONFIG, calculateHiringCost } from '../../../config/contract-config';
import { InventoryItem } from '../../../types/inventory';
import MercenaryDetailModal from '../../modals/MercenaryDetailModal';

interface TavernInteractionProps {
    mercenary: Mercenary;
    onBack: () => void;
}

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

type InteractionStep = 'IDLE' | 'CONFIRM_HIRE' | 'CONFIRM_FIRE';

const TavernInteraction: React.FC<TavernInteractionProps> = ({ mercenary, onBack }) => {
    const { state, actions } = useGame();
    const [dialogue, setDialogue] = useState(`(You sit across from ${mercenary.name}.)`);
    const [showGiftMenu, setShowGiftMenu] = useState(false);
    const [showDetail, setShowDetail] = useState(false);
    const [pendingGiftItem, setPendingGiftItem] = useState<InventoryItem | null>(null);
    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);

    // Step-based interaction state
    const [step, setStep] = useState<InteractionStep>('IDLE');

    const isHired = mercenary.status === 'HIRED' || mercenary.status === 'ON_EXPEDITION' || mercenary.status === 'INJURED';
    const isOnExpedition = mercenary.status === 'ON_EXPEDITION';
    const hiringCost = calculateHiringCost(mercenary.level, mercenary.job);
    const canAfford = state.stats.gold >= hiringCost;
    const hasAffinity = mercenary.affinity >= CONTRACT_CONFIG.HIRE_AFFINITY_THRESHOLD;

    const handleTalk = () => {
        if (pendingGiftItem || step !== 'IDLE') return;

        if (!state.talkedToToday.includes(mercenary.id)) {
            actions.talkMercenary(mercenary.id);
            const newHearts = Array.from({ length: 5 }).map((_, i) => ({
                id: Date.now() + i,
                left: 40 + Math.random() * 20,
                delay: Math.random() * 0.5,
                size: 16 + Math.random() * 12
            }));
            setFloatingHearts(prev => [...prev, ...newHearts]);
            setTimeout(() => setFloatingHearts([]), 3000);
        }

        const lines = [
            "The road is long, but a warm fire makes it easier.",
            "I heard rumors of rare ores in the Rat Cellar...",
            "What's your specialty, smith? I need something that won't break.",
            "Business seems slow today. Maybe I can help with that later.",
            "I've seen many forges, but yours has... potential.",
            "Tell me, do you have any ale left?",
            "I'm looking for work. Something that pays in gold and glory."
        ];
        setDialogue(lines[Math.floor(Math.random() * lines.length)]);
    };

    // --- Hiring Flow ---
    const handleRecruitInit = () => {
        if (!hasAffinity) {
            setDialogue("I don't know you well enough to pledge my blade to your forge yet.");
            return;
        }
        if (!canAfford) {
            setDialogue(`The contract is ${hiringCost} gold. Come back when you have the coin.`);
            return;
        }
        setStep('CONFIRM_HIRE');
        setDialogue(`"A contract for ${hiringCost} Gold? Are you certain you want me on your squad?"`);
    };

    const handleConfirmHire = () => {
        actions.hireMercenary(mercenary.id, hiringCost);
        setStep('IDLE');
        setDialogue("A fair contract. My strength is yours, Lockhart.");
    };

    // --- Termination Flow ---
    const handleTerminateInit = () => {
        setStep('CONFIRM_FIRE');
        setDialogue(`(Surprised) "Terminate the contract? Did I fail you in some way? If you let me go now, I might not return for some time."`);
    };

    const handleConfirmTerminate = () => {
        actions.fireMercenary(mercenary.id);
        setStep('IDLE');
        setDialogue(`"I see. Perhaps our paths will cross again on another road. Farewell, smith."`);
    };

    const handleRecall = () => {
        if (mercenary.assignedExpeditionId) {
            if (window.confirm("Abort current mission and recall the entire squad? No rewards will be gained.")) {
                actions.abortExpedition(mercenary.assignedExpeditionId);
                setDialogue("(Heavy breathing) We're back. The mission was too hazardous... we had to retreat.");
            }
        }
    };

    const handleCancelStep = () => {
        setStep('IDLE');
        setDialogue(`"I'm glad we cleared that up."`);
    };

    const handleSelectItemForGift = (item: InventoryItem) => {
        setPendingGiftItem(item);
        setShowGiftMenu(false);
        const raritySuffix = item.type === 'EQUIPMENT' ? ` (${item.equipmentData?.rarity})` : '';
        setDialogue(`(You hold out the ${item.name}${raritySuffix}.) "Would you like this?"`);
    };

    const handleConfirmGift = () => {
        if (!pendingGiftItem) return;
        const item = pendingGiftItem;
        actions.giveGift(mercenary.id, item.id);
        if (item.type === 'EQUIPMENT') {
            setDialogue(`(Surprised) "Is this for me? A ${item.name}? I will carry it with honor."`);
        } else {
            setDialogue(`${mercenary.name} seems pleased with the gift. "For me? You're too kind."`);
        }
        setPendingGiftItem(null);
    };

    const handleCancelGift = () => {
        setPendingGiftItem(null);
        setDialogue(`(You pull your hand back.) "Actually, never mind."`);
    };

    const giftableItems = state.inventory.filter(i => 
        i.type === 'RESOURCE' || 
        i.type === 'CONSUMABLE' || 
        i.type === 'EQUIPMENT' ||
        i.type === 'SCROLL'
    );

    const getRarityColor = (rarity?: string) => {
        switch (rarity) {
            case 'Common': return 'text-stone-400';
            case 'Uncommon': return 'text-emerald-400';
            case 'Rare': return 'text-blue-400';
            case 'Epic': return 'text-purple-400';
            case 'Legendary': return 'text-amber-400';
            default: return 'text-stone-500';
        }
    };

    const getItemImageUrl = (item: InventoryItem) => {
        if (item.type === 'SCROLL') return getAssetUrl('scroll.png');
        if (item.id.startsWith('scroll_') || item.id.startsWith('recipe_scroll_')) return getAssetUrl('scroll.png');
        if (item.type === 'EQUIPMENT' && item.equipmentData) {
            if (item.equipmentData.image) return getAssetUrl(item.equipmentData.image);
            return item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`);
        }
        return getAssetUrl(`${item.id}.png`);
    };

    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden flex flex-col items-center justify-center">

            <style>
                {`
                    @keyframes heartFloatUp {
                        0% { transform: translateY(0) translateX(0) scale(0.5); opacity: 0; }
                        20% { opacity: 1; }
                        100% { transform: translateY(-300px) translateX(var(--wobble)) scale(1.2); opacity: 0; }
                    }
                    .animate-heart {
                        animation: heartFloatUp 2.5s ease-out forwards;
                    }
                `}
            </style>

            <div className="absolute inset-0 z-0">
                <img 
                    src={getAssetUrl('tavern_bg.jpeg')} 
                    alt="Tavern Interior" 
                    className="absolute inset-0 w-full h-full object-cover opacity-50"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #1c1917, #0c0a09)';
                    }}
                />
                <div className="absolute inset-0 bg-black/40"></div>
            </div>

            {/* Mercenary Info HUD */}
            <div className="absolute top-4 left-4 z-40 animate-in slide-in-from-left-4 duration-500 w-[32%] max-w-[180px] md:max-w-[240px]">
                <div className="bg-stone-900/90 border border-stone-700 p-2.5 md:p-4 rounded-xl backdrop-blur-md shadow-2xl">
                    <div className="flex justify-between items-center mb-1.5 md:mb-2.5">
                        <div className="flex flex-col leading-tight min-w-0">
                            <span className="font-black text-amber-500 text-[8px] md:text-[10px] tracking-widest uppercase truncate">{mercenary.job}</span>
                            <span className="text-stone-500 text-[8px] md:text-[10px] font-mono">Lv.{mercenary.level}</span>
                        </div>
                        <div className="flex items-center gap-1 text-pink-400 font-bold bg-pink-950/20 px-1 md:px-1.5 py-0.5 rounded border border-pink-900/30 shrink-0">
                            <Heart className="w-2.5 h-2.5 md:w-3.5 md:h-3.5 fill-pink-400" />
                            <span className="font-mono text-[9px] md:text-xs">{mercenary.affinity}</span>
                        </div>
                    </div>

                    <div className="space-y-1.5 md:space-y-2.5">
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>HP</span>
                                <span>{Math.floor(mercenary.currentHp)}/{mercenary.maxHp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-red-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentHp / mercenary.maxHp) * 100}%` }}></div>
                            </div>
                        </div>
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>MP</span>
                                <span>{Math.floor(mercenary.currentMp)}/{mercenary.maxMp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-blue-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentMp / mercenary.maxMp) * 100}%` }}></div>
                            </div>
                        </div>
                    </div>
                    {isOnExpedition && (
                        <div className="mt-3 bg-blue-950/40 border border-blue-700/30 rounded-lg p-1.5 flex flex-col items-center">
                            <span className="text-[7px] font-black text-blue-400 uppercase tracking-widest animate-pulse">On Expedition</span>
                            <button 
                                onClick={handleRecall}
                                className="mt-1 w-full py-1 bg-red-900/60 hover:bg-red-800 text-white rounded text-[8px] font-black uppercase flex items-center justify-center gap-1 transition-all"
                            >
                                <Ban className="w-2.5 h-2.5" /> Force Recall
                            </button>
                        </div>
                    )}
                </div>
            </div>

            <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
               <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-700 ease-out">
                   <div className="relative h-[75dvh] md:h-[110dvh] w-auto flex justify-center bottom-[12dvh] md:bottom-0 md:translate-y-[20dvh]">
                       <img 
                           src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')} 
                           alt={mercenary.name}
                           className="h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_100px_rgba(0,0,0,1)]"
                       />
                       <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-3xl rounded-full -z-10"></div>

                       {floatingHearts.map(heart => (
                           <Heart 
                                key={heart.id}
                                className="absolute animate-heart fill-pink-500 text-pink-400 drop-shadow-[0_0_8px_rgba(236,72,153,0.6)]"
                                style={{
                                    left: `${heart.left}%`,
                                    bottom: '30%',
                                    width: heart.size,
                                    height: heart.size,
                                    animationDelay: `${heart.delay}s`,
                                    '--wobble': `${(Math.random() - 0.5) * 40}px`
                                } as React.CSSProperties}
                           />
                       ))}
                   </div>
               </div>
            </div>

            <div className="absolute bottom-0 w-full h-[35dvh] md:h-64 z-20 flex items-end justify-center pointer-events-none">
                <div className="w-full h-full bg-[#2a1e16] border-t-4 md:border-t-[8px] border-[#3e2723] shadow-[0_-40px_60px_rgba(0,0,0,0.85)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                    <div className="absolute inset-0 bg-gradient-to-b from-black/40 to-transparent"></div>
                </div>
            </div>

            {/* Bottom UI Unit */}
            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center gap-[10px] pb-[env(safe-area-inset-bottom)] pointer-events-none">
                {/* Interaction Action Bar */}
                <div 
                    className={`flex flex-wrap items-center justify-end gap-1.5 md:gap-3 px-4 w-full py-2 pointer-events-auto transition-opacity duration-500 ${(pendingGiftItem || step !== 'IDLE') ? 'opacity-30 pointer-events-none grayscale' : 'opacity-100'}`}
                >
                    <button 
                        onClick={handleTalk}
                        className="flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                    >
                        <MessageSquare className="w-3 h-3 md:w-4 md:h-4 text-amber-500" />
                        <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">Talk</span>
                    </button>

                    <button 
                        onClick={() => setShowGiftMenu(true)}
                        className="flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 hover:border-pink-500 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                    >
                        <Gift className="w-3 h-3 md:w-4 md:h-4 text-pink-500" />
                        <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">Gift</span>
                    </button>

                    {/* Recruit or Terminate Button */}
                    {isHired ? (
                        <button 
                            onClick={handleTerminateInit}
                            disabled={isOnExpedition}
                            className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 border rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 text-white ${isOnExpedition ? 'bg-stone-900 border-stone-800 text-stone-600 cursor-not-allowed opacity-50' : 'bg-red-950/60 hover:bg-red-900/80 border border-red-800'}`}
                        >
                            <UserMinus className="w-3 h-3 md:w-4 md:h-4" />
                            <span className="font-black text-[9px] md:text-xs uppercase tracking-widest">Terminate</span>
                        </button>
                    ) : (
                        <button 
                            onClick={handleRecruitInit}
                            disabled={!canAfford || !hasAffinity}
                            className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 border rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 ${
                                (!canAfford || !hasAffinity) 
                                ? 'bg-stone-950/80 border-stone-800 text-stone-600 grayscale cursor-not-allowed' 
                                : 'bg-amber-900/65 hover:bg-amber-800 border-amber-500 text-white'
                            }`}
                        >
                            <UserPlus className="w-3 h-3 md:w-4 md:h-4" />
                            <div className="flex flex-col items-start leading-none">
                                <span className="font-black text-[9px] md:text-xs uppercase tracking-widest">Recruit</span>
                                {hasAffinity && <span className="text-[7px] md:text-[8px] font-mono opacity-70">{hiringCost}G</span>}
                            </div>
                        </button>
                    )}

                    <button 
                        onClick={() => setShowDetail(true)}
                        className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 ${isHired ? 'hover:border-emerald-500' : 'hover:border-blue-500'}`}
                    >
                        {isHired ? <Wrench className="w-3 h-3 md:w-4 md:h-4 text-emerald-500" /> : <Search className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />}
                        <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">
                            {isHired ? 'Manage' : 'Inspect'}
                        </span>
                    </button>

                    <button 
                        onClick={onBack}
                        className="flex items-center gap-1.5 md:gap-2 px-3 md:px-5 py-2.5 md:py-3.5 bg-red-950/45 hover:bg-red-900/60 border border-red-900/50 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                    >
                        <LogOut className="w-3 h-3 md:w-4 md:h-4 text-red-500" />
                    </button>
                </div>

                <DialogueBox 
                    speaker={mercenary.name}
                    text={dialogue}
                    options={
                        pendingGiftItem ? [
                            { label: `Give ${pendingGiftItem.name}`, action: handleConfirmGift, variant: 'primary' },
                            { label: "Cancel", action: handleCancelGift, variant: 'neutral' }
                        ] : 
                        step === 'CONFIRM_HIRE' ? [
                            { label: `Sign Contract (-${hiringCost}G)`, action: handleConfirmHire, variant: 'primary' },
                            { label: "Think again", action: handleCancelStep, variant: 'neutral' }
                        ] : 
                        step === 'CONFIRM_FIRE' ? [
                            { label: "Terminate Contract", action: handleConfirmTerminate, variant: 'danger' },
                            { label: "Stay with me", action: handleCancelStep, variant: 'neutral' }
                        ] : []
                    }
                    className="w-full relative pointer-events-auto"
                />
            </div>

            {showGiftMenu && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200 p-4">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 max-h-[85vh]">
                        <div className="p-3 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-2">
                                <div className="bg-pink-900/30 p-1.5 rounded-lg border border-pink-700/50">
                                    <Gift className="w-4 h-4 text-pink-500" />
                                </div>
                                <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Select Gift</h3>
                            </div>
                            <button onClick={() => setShowGiftMenu(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors">
                                <X className="w-4 h-4" />
                            </button>
                        </div>
                        <div className="p-3 overflow-y-auto grid grid-cols-2 gap-2 custom-scrollbar flex-1 min-h-0">
                            {giftableItems.length === 0 ? (
                                <div className="col-span-2 py-12 text-center opacity-50">
                                    <Package className="w-8 h-8 text-stone-500 mx-auto mb-2" />
                                    <p className="text-[10px] text-stone-600 italic">Inventory is empty.</p>
                                </div>
                            ) : (
                                giftableItems.map(item => {
                                    const isEquipment = item.type === 'EQUIPMENT';
                                    const rarity = item.equipmentData?.rarity;
                                    const rarityColor = getRarityColor(rarity);

                                    return (
                                        <button 
                                            key={item.id} 
                                            onClick={() => handleSelectItemForGift(item)}
                                            className={`flex items-center gap-2 p-2 bg-stone-800 hover:bg-stone-750 border rounded-xl transition-all group text-left ${isEquipment ? 'border-amber-900/30' : 'border-stone-700'}`}
                                        >
                                            <div className="w-8 h-8 bg-stone-950 rounded-lg border border-stone-800 flex items-center justify-center text-lg shrink-0">
                                                <img src={getItemImageUrl(item)} className="w-6 h-6 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                                <span className="hidden text-xl">📦</span>
                                            </div>
                                            <div className="min-w-0 flex-1">
                                                <div className={`text-[10px] font-bold truncate ${isEquipment ? 'text-stone-200' : 'text-stone-300'}`}>{item.name}</div>
                                                <div className="flex items-center gap-1 leading-none mt-0.5">
                                                    {isEquipment ? (
                                                        <span className={`text-[7px] font-black uppercase tracking-tighter ${rarityColor}`}>{rarity}</span>
                                                    ) : (
                                                        <div className="text-[8px] text-stone-500 font-mono">x{item.quantity}</div>
                                                    )}
                                                </div>
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                    </div>
                </div>
            )}

            {showDetail && (
                <MercenaryDetailModal 
                    mercenary={mercenary}
                    onClose={() => setShowDetail(false)}
                    onUnequip={(mercId, slot) => actions.unequipItem(mercId, slot)}
                    isReadOnly={!isHired || isOnExpedition}
                />
            )}
        </div>
    );
};

export default TavernInteraction;

import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { ArrowLeft, Heart, Coins, Gift, MessageSquare, UserPlus, Info, Zap, Package, X, ChevronRight, Search, Wrench, LogOut, Star, UserMinus, Ban } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { Mercenary } from '../../../models/Mercenary';
import { CONTRACT_CONFIG, calculateHiringCost } from '../../../config/contract-config';
import { InventoryItem } from '../../../types/inventory';
import MercenaryDetailModal from '../../modals/MercenaryDetailModal';

interface TavernInteractionProps {
    mercenary: Mercenary;
    onBack: () => void;
}

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

type InteractionStep = 'IDLE' | 'CONFIRM_HIRE' | 'CONFIRM_FIRE';

const TavernInteraction: React.FC<TavernInteractionProps> = ({ mercenary, onBack }) => {
    const { state, actions } = useGame();
    const [dialogue, setDialogue] = useState(`(You sit across from ${mercenary.name}.)`);
    const [showGiftMenu, setShowGiftMenu] = useState(false);
    const [showDetail, setShowDetail] = useState(false);
    const [pendingGiftItem, setPendingGiftItem] = useState<InventoryItem | null>(null);
    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);

    // Step-based interaction state
    const [step, setStep] = useState<InteractionStep>('IDLE');

    const isHired = mercenary.status === 'HIRED' || mercenary.status === 'ON_EXPEDITION' || mercenary.status === 'INJURED';
    const isOnExpedition = mercenary.status === 'ON_EXPEDITION';
    const hiringCost = calculateHiringCost(mercenary.level, mercenary.job);
    const canAfford = state.stats.gold >= hiringCost;
    const hasAffinity = mercenary.affinity >= CONTRACT_CONFIG.HIRE_AFFINITY_THRESHOLD;

    const handleTalk = () => {
        if (pendingGiftItem || step !== 'IDLE') return;

        if (!state.talkedToToday.includes(mercenary.id)) {
            actions.talkMercenary(mercenary.id);
            const newHearts = Array.from({ length: 5 }).map((_, i) => ({
                id: Date.now() + i,
                left: 40 + Math.random() * 20,
                delay: Math.random() * 0.5,
                size: 16 + Math.random() * 12
            }));
            setFloatingHearts(prev => [...prev, ...newHearts]);
            setTimeout(() => setFloatingHearts([]), 3000);
        }

        const lines = [
            "The road is long, but a warm fire makes it easier.",
            "I heard rumors of rare ores in the Rat Cellar...",
            "What's your specialty, smith? I need something that won't break.",
            "Business seems slow today. Maybe I can help with that later.",
            "I've seen many forges, but yours has... potential.",
            "Tell me, do you have any ale left?",
            "I'm looking for work. Something that pays in gold and glory."
        ];
        setDialogue(lines[Math.floor(Math.random() * lines.length)]);
    };

    // --- Hiring Flow ---
    const handleRecruitInit = () => {
        if (!hasAffinity) {
            setDialogue("I don't know you well enough to pledge my blade to your forge yet.");
            return;
        }
        if (!canAfford) {
            setDialogue(`The contract is ${hiringCost} gold. Come back when you have the coin.`);
            return;
        }
        setStep('CONFIRM_HIRE');
        setDialogue(`"A contract for ${hiringCost} Gold? Are you certain you want me on your squad?"`);
    };

    const handleConfirmHire = () => {
        actions.hireMercenary(mercenary.id, hiringCost);
        setStep('IDLE');
        setDialogue("A fair contract. My strength is yours, Lockhart.");
    };

    // --- Termination Flow ---
    const handleTerminateInit = () => {
        setStep('CONFIRM_FIRE');
        setDialogue(`(Surprised) "Terminate the contract? Did I fail you in some way? If you let me go now, I might not return for some time."`);
    };

    const handleConfirmTerminate = () => {
        actions.fireMercenary(mercenary.id);
        setStep('IDLE');
        setDialogue(`"I see. Perhaps our paths will cross again on another road. Farewell, smith."`);
    };

    const handleRecall = () => {
        if (mercenary.assignedExpeditionId) {
            if (window.confirm("Abort current mission and recall the entire squad? No rewards will be gained.")) {
                actions.abortExpedition(mercenary.assignedExpeditionId);
                setDialogue("(Heavy breathing) We're back. The mission was too hazardous... we had to retreat.");
            }
        }
    };

    const handleCancelStep = () => {
        setStep('IDLE');
        setDialogue(`"I'm glad we cleared that up."`);
    };

    const handleSelectItemForGift = (item: InventoryItem) => {
        setPendingGiftItem(item);
        setShowGiftMenu(false);
        const raritySuffix = item.type === 'EQUIPMENT' ? ` (${item.equipmentData?.rarity})` : '';
        setDialogue(`(You hold out the ${item.name}${raritySuffix}.) "Would you like this?"`);
    };

    const handleConfirmGift = () => {
        if (!pendingGiftItem) return;
        const item = pendingGiftItem;
        actions.giveGift(mercenary.id, item.id);
        if (item.type === 'EQUIPMENT') {
            setDialogue(`(Surprised) "Is this for me? A ${item.name}? I will carry it with honor."`);
        } else {
            setDialogue(`${mercenary.name} seems pleased with the gift. "For me? You're too kind."`);
        }
        setPendingGiftItem(null);
    };

    const handleCancelGift = () => {
        setPendingGiftItem(null);
        setDialogue(`(You pull your hand back.) "Actually, never mind."`);
    };

    const giftableItems = state.inventory.filter(i => 
        i.type === 'RESOURCE' || 
        i.type === 'CONSUMABLE' || 
        i.type === 'EQUIPMENT' ||
        i.type === 'SCROLL'
    );

    const getRarityColor = (rarity?: string) => {
        switch (rarity) {
            case 'Common': return 'text-stone-400';
            case 'Uncommon': return 'text-emerald-400';
            case 'Rare': return 'text-blue-400';
            case 'Epic': return 'text-purple-400';
            case 'Legendary': return 'text-amber-400';
            default: return 'text-stone-500';
        }
    };

    const getItemImageUrl = (item: InventoryItem) => {
        if (item.type === 'SCROLL') return getAssetUrl('scroll.png');
        if (item.id.startsWith('scroll_') || item.id.startsWith('recipe_scroll_')) return getAssetUrl('scroll.png');
        if (item.type === 'EQUIPMENT' && item.equipmentData) {
            if (item.equipmentData.image) return getAssetUrl(item.equipmentData.image);
            return item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`);
        }
        return getAssetUrl(`${item.id}.png`);
    };

    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden flex flex-col items-center justify-center">

            <style>
                {`
                    @keyframes heartFloatUp {
                        0% { transform: translateY(0) translateX(0) scale(0.5); opacity: 0; }
                        20% { opacity: 1; }
                        100% { transform: translateY(-300px) translateX(var(--wobble)) scale(1.2); opacity: 0; }
                    }
                    .animate-heart {
                        animation: heartFloatUp 2.5s ease-out forwards;
                    }
                `}
            </style>

            <div className="absolute inset-0 z-0">
                <img 
                    src={getAssetUrl('tavern_bg.jpeg')} 
                    alt="Tavern Interior" 
                    className="absolute inset-0 w-full h-full object-cover opacity-50"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #1c1917, #0c0a09)';
                    }}
                />
                <div className="absolute inset-0 bg-black/40"></div>
            </div>

            {/* Mercenary Info HUD */}
            <div className="absolute top-4 left-4 z-40 animate-in slide-in-from-left-4 duration-500 w-[32%] max-w-[180px] md:max-w-[240px]">
                <div className="bg-stone-900/90 border border-stone-700 p-2.5 md:p-4 rounded-xl backdrop-blur-md shadow-2xl">
                    <div className="flex justify-between items-center mb-1.5 md:mb-2.5">
                        <div className="flex flex-col leading-tight min-w-0">
                            <span className="font-black text-amber-500 text-[8px] md:text-[10px] tracking-widest uppercase truncate">{mercenary.job}</span>
                            <span className="text-stone-500 text-[8px] md:text-[10px] font-mono">Lv.{mercenary.level}</span>
                        </div>
                        <div className="flex items-center gap-1 text-pink-400 font-bold bg-pink-950/20 px-1 md:px-1.5 py-0.5 rounded border border-pink-900/30 shrink-0">
                            <Heart className="w-2.5 h-2.5 md:w-3.5 md:h-3.5 fill-pink-400" />
                            <span className="font-mono text-[9px] md:text-xs">{mercenary.affinity}</span>
                        </div>
                    </div>

                    <div className="space-y-1.5 md:space-y-2.5">
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>HP</span>
                                <span>{Math.floor(mercenary.currentHp)}/{mercenary.maxHp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-red-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentHp / mercenary.maxHp) * 100}%` }}></div>
                            </div>
                        </div>
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>MP</span>
                                <span>{Math.floor(mercenary.currentMp)}/{mercenary.maxMp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-blue-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentMp / mercenary.maxMp) * 100}%` }}></div>
                            </div>
                        </div>
                    </div>
                    {isOnExpedition && (
                        <div className="mt-3 bg-blue-950/40 border border-blue-700/30 rounded-lg p-1.5 flex flex-col items-center">
                            <span className="text-[7px] font-black text-blue-400 uppercase tracking-widest animate-pulse">On Expedition</span>
                            <button 
                                onClick={handleRecall}
                                className="mt-1 w-full py-1 bg-red-900/60 hover:bg-red-800 text-white rounded text-[8px] font-black uppercase flex items-center justify-center gap-1 transition-all"
                            >
                                <Ban className="w-2.5 h-2.5" /> Force Recall
                            </button>
                        </div>
                    )}
                </div>
            </div>

            <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
               <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-700 ease-out">
                   <div className="relative h-[75dvh] md:h-[110dvh] w-auto flex justify-center bottom-[12dvh] md:bottom-0 md:translate-y-[20dvh]">
                       <img 
                           src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')} 
                           alt={mercenary.name}
                           className="h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_100px_rgba(0,0,0,1)]"
                       />
                       <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-3xl rounded-full -z-10"></div>

                       {floatingHearts.map(heart => (
                           <Heart 
                                key={heart.id}
                                className="absolute animate-heart fill-pink-500 text-pink-400 drop-shadow-[0_0_8px_rgba(236,72,153,0.6)]"
                                style={{
                                    left: `${heart.left}%`,
                                    bottom: '30%',
                                    width: heart.size,
                                    height: heart.size,
                                    animationDelay: `${heart.delay}s`,
                                    '--wobble': `${(Math.random() - 0.5) * 40}px`
                                } as React.CSSProperties}
                           />
                       ))}
                   </div>
               </div>
            </div>

            <div className="absolute bottom-0 w-full h-[35dvh] md:h-64 z-20 flex items-end justify-center pointer-events-none">
                <div className="w-full h-full bg-[#2a1e16] border-t-4 md:border-t-[8px] border-[#3e2723] shadow-[0_-40px_60px_rgba(0,0,0,0.85)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                    <div className="absolute inset-0 bg-gradient-to-b from-black/40 to-transparent"></div>
                </div>
            </div>

            {/* Bottom UI Unit */}
            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center gap-[10px] pb-[env(safe-area-inset-bottom)] pointer-events-none">

                {/* Interaction Action Bars */}
                <div className={`flex flex-col items-end gap-2 w-full px-4 py-2 pointer-events-auto transition-opacity duration-500 ${(pendingGiftItem || step !== 'IDLE') ? 'opacity-30 pointer-events-none grayscale' : 'opacity-100'}`}>

                    {/* Top Row: 나가기 버튼 단독 배치 */}
                    <div className="flex justify-end w-full">
                        <button 
                            onClick={onBack}
                            className="flex items-center gap-1.5 md:gap-2 px-3 md:px-5 py-2 md:py-3 bg-red-950/45 hover:bg-red-900/60 border border-red-900/50 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                        >
                            <LogOut className="w-3 h-3 md:w-4 md:h-4 text-red-500" />
                        </button>
                    </div>

                    {/* Bottom Row: 기능 버튼들 (우측 정렬 & 개행 가능) */}
                    <div className="flex flex-wrap items-center justify-end gap-1.5 md:gap-3 w-full">
                        <button 
                            onClick={handleTalk}
                            className="flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                        >
                            <MessageSquare className="w-3 h-3 md:w-4 md:h-4 text-amber-500" />
                            <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">Talk</span>
                        </button>

                        <button 
                            onClick={() => setShowGiftMenu(true)}
                            className="flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 hover:border-pink-500 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                        >
                            <Gift className="w-3 h-3 md:w-4 md:h-4 text-pink-500" />
                            <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">Gift</span>
                        </button>

                        {/* Recruit or Terminate Button */}
                        {isHired ? (
                            <button 
                                onClick={handleTerminateInit}
                                disabled={isOnExpedition}
                                className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 border rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 text-white ${isOnExpedition ? 'bg-stone-900 border-stone-800 text-stone-600 cursor-not-allowed opacity-50' : 'bg-red-950/60 hover:bg-red-900/80 border border-red-800'}`}
                            >
                                <UserMinus className="w-3 h-3 md:w-4 md:h-4" />
                                <span className="font-black text-[9px] md:text-xs uppercase tracking-widest">Terminate</span>
                            </button>
                        ) : (
                            <button 
                                onClick={handleRecruitInit}
                                disabled={!canAfford || !hasAffinity}
                                className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 border rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 ${
                                    (!canAfford || !hasAffinity) 
                                    ? 'bg-stone-950/80 border-stone-800 text-stone-600 grayscale cursor-not-allowed' 
                                    : 'bg-amber-900/65 hover:bg-amber-800 border-amber-500 text-white'
                                }`}
                            >
                                <UserPlus className="w-3 h-3 md:w-4 md:h-4" />
                                <div className="flex flex-col items-start leading-none">
                                    <span className="font-black text-[9px] md:text-xs uppercase tracking-widest">Recruit</span>
                                    {hasAffinity && <span className="text-[7px] md:text-[8px] font-mono opacity-70">{hiringCost}G</span>}
                                </div>
                            </button>
                        )}

                        <button 
                            onClick={() => setShowDetail(true)}
                            className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 ${isHired ? 'hover:border-emerald-500' : 'hover:border-blue-500'}`}
                        >
                            {isHired ? <Wrench className="w-3 h-3 md:w-4 md:h-4 text-emerald-500" /> : <Search className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />}
                            <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">
                                {isHired ? 'Manage' : 'Inspect'}
                            </span>
                        </button>
                    </div>
                </div>

                <DialogueBox 
                    speaker={mercenary.name}
                    text={dialogue}
                    options={
                        pendingGiftItem ? [
                            { label: `Give ${pendingGiftItem.name}`, action: handleConfirmGift, variant: 'primary' },
                            { label: "Cancel", action: handleCancelGift, variant: 'neutral' }
                        ] : 
                        step === 'CONFIRM_HIRE' ? [
                            { label: `Sign Contract (-${hiringCost}G)`, action: handleConfirmHire, variant: 'primary' },
                            { label: "Think again", action: handleCancelStep, variant: 'neutral' }
                        ] : 
                        step === 'CONFIRM_FIRE' ? [
                            { label: "Terminate Contract", action: handleConfirmTerminate, variant: 'danger' },
                            { label: "Stay with me", action: handleCancelStep, variant: 'neutral' }
                        ] : []
                    }
                    className="w-full relative pointer-events-auto"
                />
            </div>

            {showGiftMenu && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200 p-4">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 max-h-[85vh]">
                        <div className="p-3 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-2">
                                <div className="bg-pink-900/30 p-1.5 rounded-lg border border-pink-700/50">
                                    <Gift className="w-4 h-4 text-pink-500" />
                                </div>
                                <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Select Gift</h3>
                            </div>
                            <button onClick={() => setShowGiftMenu(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors">
                                <X className="w-4 h-4" />
                            </button>
                        </div>
                        <div className="p-3 overflow-y-auto grid grid-cols-2 gap-2 custom-scrollbar flex-1 min-h-0">
                            {giftableItems.length === 0 ? (
                                <div className="col-span-2 py-12 text-center opacity-50">
                                    <Package className="w-8 h-8 text-stone-500 mx-auto mb-2" />
                                    <p className="text-[10px] text-stone-600 italic">Inventory is empty.</p>
                                </div>
                            ) : (
                                giftableItems.map(item => {
                                    const isEquipment = item.type === 'EQUIPMENT';
                                    const rarity = item.equipmentData?.rarity;
                                    const rarityColor = getRarityColor(rarity);

                                    return (
                                        <button 
                                            key={item.id} 
                                            onClick={() => handleSelectItemForGift(item)}
                                            className={`flex items-center gap-2 p-2 bg-stone-800 hover:bg-stone-750 border rounded-xl transition-all group text-left ${isEquipment ? 'border-amber-900/30' : 'border-stone-700'}`}
                                        >
                                            <div className="w-8 h-8 bg-stone-950 rounded-lg border border-stone-800 flex items-center justify-center text-lg shrink-0">
                                                <img src={getItemImageUrl(item)} className="w-6 h-6 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                                <span className="hidden text-xl">📦</span>
                                            </div>
                                            <div className="min-w-0 flex-1">
                                                <div className={`text-[10px] font-bold truncate ${isEquipment ? 'text-stone-200' : 'text-stone-300'}`}>{item.name}</div>
                                                <div className="flex items-center gap-1 leading-none mt-0.5">
                                                    {isEquipment ? (
                                                        <span className={`text-[7px] font-black uppercase tracking-tighter ${rarityColor}`}>{rarity}</span>
                                                    ) : (
                                                        <div className="text-[8px] text-stone-500 font-mono">x{item.quantity}</div>
                                                    )}
                                                </div>
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                    </div>
                </div>
            )}

            {showDetail && (
                <MercenaryDetailModal 
                    mercenary={mercenary}
                    onClose={() => setShowDetail(false)}
                    onUnequip={(mercId, slot) => actions.unequipItem(mercId, slot)}
                    isReadOnly={!isHired || isOnExpedition}
                />
            )}
        </div>
    );
};

export default TavernInteraction;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
}

export default class DungeonScene extends Phaser.Scene {
    public add!: Phaser.GameObjects.GameObjectFactory;
    public tweens!: Phaser.Tweens.TweenManager;
    public scale!: Phaser.Scale.ScaleManager;
    public cameras!: Phaser.Cameras.Scene2D.CameraManager;
    public input!: Phaser.Input.InputPlugin;
    public time!: Phaser.Time.Clock;
    public events!: Phaser.Events.EventEmitter;
    public load!: Phaser.Loader.LoaderPlugin;
    public textures!: Phaser.Textures.TextureManager;
    public anims!: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    // 드래그 관련 변수
    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
    }

    create() {
        this.cameras.main.setBackgroundColor(0x000000);

        this.root = this.add.container(0, 0);

        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        // 스프레이 입자 설정
        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToEntrance();

        this.scale.on('resize', () => this.alignViewToEntrance(), this);
        this.setupDragControls();
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => {
            this.isDragging = false;
        });

        this.input.on('pointerout', () => {
            this.isDragging = false;
        });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            // 바닥 타일
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);

            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({
                    targets: tile,
                    alpha: 1,
                    scale: 1,
                    duration: 600,
                    ease: 'Back.easeOut'
                });
            }
            this.revealedTiles.add(key);
        }

        // 콘텐츠 갱신
        if (this.contentByCoord.has(key)) {
            this.contentByCoord.get(key)!.destroy();
        }
        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 1,
                    scale: 1,
                    duration: 500,
                    delay: 200,
                    ease: 'Cubic.easeOut'
                });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'KEY':
                content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'ENTRANCE':
                content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'GOLD':
                content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    y: y - 5,
                    duration: 1200,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'TRAP':
                content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    angle: 15,
                    duration: 500,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'NPC':
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 0.5,
                    duration: 1000,
                    yoyo: true,
                    repeat: -1
                });
                break;
        }
        if (content) {
            this.contentLayer.add(content);
        }
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);

        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);

        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);

        this.tweens.add({
            targets: visual,
            y: -8,
            duration: 800,
            yoyo: true,
            repeat: -1,
            ease: 'Sine.easeInOut'
        });
    }

    private alignViewToEntrance() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;

        // 카메라를 더 아래로 내리기 위해 yOffset을 강화 (-0.15 -> -0.3)
        // 이는 월드 컨테이너를 위로 더 밀어 올리는 효과를 줍니다.
        const yOffset = -height * 0.3;
        const currentScale = 1.0;
        this.root.setScale(currentScale);

        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);

        this.root.setPosition((width / 2) - (targetX * currentScale), (height / 2 + yOffset) - (targetY * currentScale));
    }

    public updateSession(newSession: ManualDungeonSession) {
        this.session = newSession;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);

        this.isMoving = true;

        this.tweens.add({
            targets: this.playerMarker,
            x: targetLocalX,
            y: targetLocalY,
            duration: 300,
            ease: 'Cubic.out',
            onComplete: () => {
                this.isMoving = false;
                this.drawRevealedTile(x, y, newSession.grid[y][x], true);
            }
        });
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Trophy, Sparkles, Coins, AlertTriangle, Shield, ArrowRight, Package, ChevronUp, ChevronDown
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl } from '../../../utils';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);

    // UI states
    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);

    // Victory sequence states
    const [showVictoryOverlay, setShowVictoryOverlay] = useState(false);
    const [showResultPopup, setShowResultPopup] = useState(false);
    const [hasTriggeredVictory, setHasTriggeredVictory] = useState(false);

    // Persistent tactical feedback
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');

    // Rescue interaction state
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    if (!session) return null;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return null;

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const avgEnergy = party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1);

    const currentRoomType = session.grid[session.playerPos.y][session.playerPos.x];
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';
    const isTrapNode = currentRoomType === 'TRAP';

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) {
                setIsReady(true);
            } else {
                requestAnimationFrame(checkSize);
            }
        };
        checkSize();
    }, []);

    // Monitor room entries for victory and persistent discovery messages
    useEffect(() => {
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const latestLog = state.logs[0];

        // Victory Logic
        if (session.isBossDefeated && !hasTriggeredVictory) {
            setShowVictoryOverlay(true);
            setHasTriggeredVictory(true);
            return;
        }

        if (room === 'KEY') {
            setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location. What should we do next?");
        } else if (room === 'NPC' && !session.npcFound) {
            setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols. What is the next move?");
        } else if (room === 'BOSS') {
            setLastDiscoveryMessage("Enemy High-Value Target neutralized. Area lockdown lifted. Sector secured. Extracting now?");
        } else if (room === 'TRAP') {
            setLastDiscoveryMessage("WARNING: Trap triggered! Structural integrity compromised, but area is currently safe. What should we do next?");
        } else if (isEntranceNode && (lastDiscoveryMessage === '' || lastDiscoveryMessage.includes('Infiltration'))) {
            setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep. What's our first move?`);
        } else if (room === 'EMPTY') {
            const goldTerms = ['Looted', 'Found', 'Discovered', 'cache', 'coins', 'gold'];
            const foundGold = goldTerms.some(term => latestLog?.includes(term));

            if (foundGold) {
                setLastDiscoveryMessage("Treasury cache secured. This sector is now clear and safe. What should be our next course of action?");
            } else {
                setLastDiscoveryMessage("Scans indicate this area is vacant. No immediate threats detected. What is the next move?");
            }
        }
    }, [session.playerPos, session.grid, session.npcFound, dungeon.name, isEntranceNode, state.logs, session.isBossDefeated, hasTriggeredVictory]);

    useEffect(() => {
        if (!isReady || !containerRef.current) return;

        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO,
                parent: containerRef.current,
                width: containerRef.current.clientWidth,
                height: containerRef.current.clientHeight,
                backgroundColor: 'transparent',
                transparent: true,
                scene: [DungeonScene],
                scale: {
                    mode: Phaser.Scale.RESIZE,
                    autoCenter: Phaser.Scale.CENTER_BOTH
                }
            };

            const game = new Phaser.Game(config);
            gameRef.current = game;

            game.scene.start('DungeonScene', {
                session,
                moveEnergy: dungeon.moveEnergy,
                bossEnergy: dungeon.bossEnergy,
                onMove: (dx: number, dy: number) => {
                    actions.moveInManualDungeon(dx, dy);
                }
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon.moveEnergy, dungeon.bossEnergy]);

    useEffect(() => {
        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
                gameRef.current = null;
            }
        };
    }, []);

    const handleDpadMove = (dx: number, dy: number) => {
        if (showVictoryOverlay || showResultPopup || rescueStep === 'DIALOGUE') return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleClose = () => {
        if (showVictoryOverlay || showResultPopup) return;
        actions.toggleManualDungeonOverlay(false);
    };

    const handleAbort = () => {
        actions.retreatFromManualDungeon();
        setShowAbortConfirm(false);
    };

    const handleRescueClick = () => {
        setRescueStep('DIALOGUE');
    };

    const handleRescueConfirm = () => {
        if (session.dungeonId === 'dungeon_t1_rats') {
            actions.rescueMercenary('tilly_footloose');
        }
        setRescueStep('DONE');
    };

    const navOptions = useMemo(() => {
        if (rescueStep === 'DIALOGUE') {
            return [
                { label: "Accept Escort Request", action: handleRescueConfirm, variant: 'primary' as const }
            ];
        }

        const baseOptions = [
            { 
                label: "North", 
                action: () => handleDpadMove(0, -1), 
                disabled: session.playerPos.y <= 0 
            },
            { 
                label: "South", 
                action: () => handleDpadMove(0, 1), 
                disabled: session.playerPos.y >= dungeon.gridHeight - 1 
            },
            { 
                label: "West", 
                action: () => handleDpadMove(-1, 0), 
                disabled: session.playerPos.x <= 0 
            },
            { 
                label: "East", 
                action: () => handleDpadMove(1, 0), 
                disabled: session.playerPos.x >= dungeon.gridWidth - 1 
            },
        ];

        // Add "Return to Forge" option if at entrance (allow safe extraction)
        if (isEntranceNode) {
            return [
                { label: "Return to Forge", action: actions.finishManualAssault, variant: 'neutral' as const },
                ...baseOptions
            ];
        }

        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') {
            return [
                { label: "Rescue Survivor", action: handleRescueClick, variant: 'primary' as const },
                ...baseOptions
            ];
        }

        // Add persistent "Return to Forge" option after boss is defeated
        if (session.isBossDefeated) {
            return [
                { label: "Return to Forge", action: actions.finishManualAssault, variant: 'primary' as const },
                ...baseOptions
            ];
        }

        return baseOptions;
    }, [session.playerPos, dungeon, isNPCNode, session.npcFound, rescueStep, session.isBossDefeated, actions, isEntranceNode]);

    const tacticalDialogue = useMemo(() => {
        if (session.isBossDefeated) {
            return "Mission status: CLEARED. Sector lockdown lifted. We can extract immediately or continue sweeping for secondary resources. What is our choice?";
        }

        if (isEntranceNode) {
            return "Current coordinates: Sector Entrance. Extraction point is active and secure. Should we return to the Forge or proceed further into the dungeon?";
        }

        if (rescueStep === 'DIALOGUE') {
            return "Oh! Thank the gods! I thought the rats would have me for sure. Please, lead the way out... I'll find my own way back once we're clear of this floor.";
        }

        if (isNPCNode && !session.npcFound) return "Warning: Unidentified life-sign detected in the immediate vicinity. Civilian presence confirmed. Escort protocols advised. What is the next move?";

        if (isTrapNode) {
            return "TACTICAL ALERT: Active hazard detected on current coordinates! Avoid sustained exposure. What is our next move?";
        }

        const isLowHp = party.some(m => m.currentHp < m.maxHp * 0.25);
        if (isLowHp) {
            return "MEDICAL EMERGENCY: Multiple units at critical HP. Sector secured but retreat is advised. What should we do?";
        }

        if (avgEnergy < 15) {
            return "FATIGUE CRITICAL: Squad performance degraded. Area clear but exhaustion is high. Should we extract or proceed?";
        }

        return lastDiscoveryMessage || "Scanning sector... Area clear. What's the next move?";
    }, [avgEnergy, session.hasKey, isNPCNode, session.npcFound, rescueStep, lastDiscoveryMessage, session.isBossLocked, party, isTrapNode, session.isBossDefeated, isEntranceNode]);

    const speakerName = useMemo(() => {
        if (session.isBossDefeated) return "Tactical AI";
        if (rescueStep === 'DIALOGUE') return "Tilly Footloose";
        return "Tactical Link";
    }, [session.isBossDefeated, rescueStep]);

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">

            <div ref={containerRef} className="absolute inset-0 z-0" />

            {/* Trap Warning Badge */}
            {isTrapNode && !session.isBossDefeated && !showVictoryOverlay && !showResultPopup && (
                <div className="absolute top-20 left-1/2 -translate-x-1/2 z-[55] animate-bounce">
                    <div className="bg-red-600/90 text-white px-4 py-1.5 rounded-full border-2 border-white/20 shadow-[0_0_20px_rgba(220,38,38,0.5)] flex items-center gap-2">
                        <AlertTriangle className="w-4 h-4 fill-white text-red-600" />
                        <span className="font-black text-xs uppercase tracking-tighter">Hazard Detected!</span>
                    </div>
                </div>
            )}

            {/* Squad Status HUD - Now Toggleable */}
            <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                <button 
                    onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)}
                    className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2 mb-1 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors group"
                >
                    <div className="flex items-center gap-2">
                        <Shield className="w-3.5 h-3.5 text-blue-400" />
                        <span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span>
                    </div>
                    {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" />}
                </button>

                {isSquadStatusExpanded && party.map(merc => {
                    const hpPer = (merc.currentHp / merc.maxHp) * 100;
                    const mpPer = (merc.currentMp / merc.maxMp) * 100;
                    return (
                        <div key={merc.id} className="bg-stone-900/80 border border-stone-700/50 p-2 rounded-xl backdrop-blur-md shadow-lg animate-in slide-in-from-top-2 duration-300">
                            <div className="flex items-center gap-2 mb-1.5">
                                <div className="w-6 h-6 rounded-full bg-stone-800 flex items-center justify-center border border-white/5 text-xs shadow-inner shrink-0">
                                    {merc.icon}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className="text-[10px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div>
                                    <div className="text-[7px] text-stone-500 font-bold uppercase tracking-tighter truncate">{merc.job} • LV.{merc.level}</div>
                                </div>
                            </div>
                            <div className="space-y-1">
                                <div className="flex flex-col gap-0.5">
                                    <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter"><span>HP</span><span>{Math.floor(merc.currentHp)}/{merc.maxHp}</span></div>
                                    <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                                </div>
                                <div className="flex flex-col gap-0.5">
                                    <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter"><span>MP</span><span>{Math.floor(merc.currentMp)}/{merc.maxMp}</span></div>
                                    <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} /></div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* NPC Visual Exposure Layer */}
            {rescueStep === 'DIALOGUE' && (
                <div className="absolute inset-0 z-30 flex flex-col items-center justify-end pointer-events-none pb-0 animate-in fade-in zoom-in-95 duration-700">
                    <div className="relative h-[65dvh] md:h-[85dvh] flex justify-center bottom-[20dvh] md:bottom-[10dvh]">
                        <img src={getAssetUrl('tily_footloose.png')} alt="Rescued Survivor" className="h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_50px_rgba(0,0,0,1)]" />
                    </div>
                </div>
            )}

            {/* Top Bar */}
            <div className="relative p-2 md:p-4 bg-stone-950/20 backdrop-blur-md border-b border-white/10 flex justify-between items-center shrink-0 z-50 gap-2">
                <div className="flex items-center gap-2 md:gap-4 min-w-0">
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl border flex items-center justify-center shrink-0 transition-all ${session.hasKey ? 'bg-amber-900/40 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.4)] animate-pulse' : 'bg-stone-950/50 border-stone-800'}`}><Key className={`w-5 h-5 md:w-7 md:h-7 ${session.hasKey ? 'text-amber-400' : 'text-stone-600'}`} /></div>
                    <div className="min-w-0">
                        <h2 className="text-stone-100 font-black uppercase text-xs md:text-lg leading-none drop-shadow-md truncate">{dungeon.name}</h2>
                        <div className="flex items-center gap-2 mt-1">
                             <div className="flex items-center gap-1 bg-stone-950/60 px-1.5 py-0.5 rounded border border-white/5 shrink-0"><Zap className="w-2.5 h-2.5 text-blue-500" /><span className="text-[8px] md:text-[10px] font-mono font-bold text-blue-400 uppercase tracking-tighter">{Math.floor(avgEnergy)}%</span></div>
                             {session.goldCollected > 0 && <div className="flex items-center gap-1 bg-amber-900/40 px-1.5 py-0.5 rounded border border-amber-600/30 shrink-0"><Coins className="w-2.5 h-2.5 text-amber-400" /><span className="text-[8px] md:text-[10px] font-mono font-bold text-amber-200 uppercase tracking-tighter">+{session.goldCollected}</span></div>}
                             {session.npcFound && <div className="flex items-center gap-1 bg-amber-950/60 px-1.5 py-0.5 rounded border border-amber-500/20 shrink-0 animate-pulse"><Sparkles className="w-2.5 h-2.5 text-amber-500" /><span className="text-[8px] md:text-[10px] font-black text-amber-400 uppercase">Rescued</span></div>}
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-1 md:gap-2 shrink-0">
                    <button onClick={() => !session.isBossDefeated && setShowAbortConfirm(true)} disabled={session.isBossDefeated} className={`flex items-center gap-1 md:gap-2 px-2 md:px-3 py-1.5 md:py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/50 rounded-lg text-red-400 font-bold text-[9px] md:text-[10px] transition-all backdrop-blur-md ${session.isBossDefeated ? 'opacity-30 cursor-not-allowed' : ''}`}><LogOut className="w-3 h-3 md:w-3.5 md:h-3.5" /> <span className="hidden xs:inline">Abort</span></button>
                    <button onClick={handleClose} disabled={showVictoryOverlay || showResultPopup} className={`flex items-center gap-1 md:gap-2 px-2 md:px-4 py-1.5 md:py-2 bg-stone-800/60 hover:bg-stone-700/80 border border-white/10 rounded-lg text-stone-200 font-bold text-[9px] md:text-xs transition-all backdrop-blur-md ${(showVictoryOverlay || showResultPopup) ? 'opacity-30 cursor-not-allowed' : ''}`}><X className="w-3 h-3 md:w-4 md:h-4" /> <span>Pause</span></button>
                </div>
            </div>

            <div className="flex-1 pointer-events-none" />

            {/* Tactical Dialogue Area */}
            <div className="relative z-40">
                <DialogueBox speaker={speakerName} text={tacticalDialogue} options={(showVictoryOverlay || showResultPopup) ? [] : (navOptions as any)} />
            </div>

            <ConfirmationModal 
                isOpen={showAbortConfirm}
                title="Abandon Assault?"
