                </div>
            )}
        </div>
    );
};

export default AssaultNavigator;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
}

export default class DungeonScene extends Phaser.Scene {
    public add!: Phaser.GameObjects.GameObjectFactory;
    public tweens!: Phaser.Tweens.TweenManager;
    public scale!: Phaser.Scale.ScaleManager;
    public cameras!: Phaser.Cameras.Scene2D.CameraManager;
    public input!: Phaser.Input.InputPlugin;
    public time!: Phaser.Time.Clock;
    public events!: Phaser.Events.EventEmitter;
    public load!: Phaser.Loader.LoaderPlugin;
    public textures!: Phaser.Textures.TextureManager;
    public anims!: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    // 드래그 관련 변수
    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
    }

    create() {
        this.cameras.main.setBackgroundColor(0x000000);

        this.root = this.add.container(0, 0);

        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        // 스프레이 입자 설정
        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToEntrance();

        this.scale.on('resize', () => this.alignViewToEntrance(), this);
        this.setupDragControls();
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => {
            this.isDragging = false;
        });

        this.input.on('pointerout', () => {
            this.isDragging = false;
        });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            // 바닥 타일
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);

            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({
                    targets: tile,
                    alpha: 1,
                    scale: 1,
                    duration: 600,
                    ease: 'Back.easeOut'
                });
            }
            this.revealedTiles.add(key);
        }

        // 콘텐츠 갱신
        if (this.contentByCoord.has(key)) {
            this.contentByCoord.get(key)!.destroy();
        }
        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 1,
                    scale: 1,
                    duration: 500,
                    delay: 200,
                    ease: 'Cubic.easeOut'
                });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'KEY':
                content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'ENTRANCE':
                content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'GOLD':
                content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    y: y - 5,
                    duration: 1200,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'TRAP':
                content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    angle: 15,
                    duration: 500,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'NPC':
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 0.5,
                    duration: 1000,
                    yoyo: true,
                    repeat: -1
                });
                break;
        }
        if (content) {
            this.contentLayer.add(content);
        }
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);

        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);

        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);

        this.tweens.add({
            targets: visual,
            y: -8,
            duration: 800,
            yoyo: true,
            repeat: -1,
            ease: 'Sine.easeInOut'
        });
    }

    private alignViewToEntrance() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;

        // yOffset을 양수 * 0.2로 조정하여 시점을 중앙보다 약간 아래로 내림
        const yOffset = height * 0.2;
        const currentScale = 1.0;
        this.root.setScale(currentScale);

        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);

        this.root.setPosition((width / 2) - (targetX * currentScale), (height / 2 + yOffset) - (targetY * currentScale));
    }

    public updateSession(newSession: ManualDungeonSession) {
        this.session = newSession;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);

        this.isMoving = true;

        this.tweens.add({
            targets: this.playerMarker,
            x: targetLocalX,
            y: targetLocalY,
            duration: 300,
            ease: 'Cubic.out',
            onComplete: () => {
                this.isMoving = false;
                this.drawRevealedTile(x, y, newSession.grid[y][x], true);
            }
        });
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Trophy, Sparkles, Coins, AlertTriangle, Shield, ArrowRight, Package, ChevronUp, ChevronDown
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl } from '../../../utils';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);
    const [showRetreatAtEntranceConfirm, setShowRetreatAtEntranceConfirm] = useState(false);

    // UI states
    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);

    // Victory sequence states
    const [showVictoryOverlay, setShowVictoryOverlay] = useState(false);
    const [showResultPopup, setShowResultPopup] = useState(false);
    const [hasTriggeredVictory, setHasTriggeredVictory] = useState(false);

    // Persistent tactical feedback
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');

    // Rescue interaction state
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    if (!session) return null;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return null;

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const avgEnergy = party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1);

    const currentRoomType = session.grid[session.playerPos.y][session.playerPos.x];
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';
    const isBossNode = currentRoomType === 'BOSS';
    const isTrapNode = currentRoomType === 'TRAP';

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) {
                setIsReady(true);
            } else {
                requestAnimationFrame(checkSize);
            }
        };
        checkSize();
    }, []);

    // Monitor room entries for victory and persistent discovery messages
    useEffect(() => {
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const latestLog = state.logs[0];

        // Victory Logic
        if (session.isBossDefeated && !hasTriggeredVictory) {
            setShowVictoryOverlay(true);
            setHasTriggeredVictory(true);
            return;
        }

        if (room === 'KEY') {
            setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location. What should we do next?");
        } else if (room === 'NPC' && !session.npcFound) {
            setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols. What is the next move?");
        } else if (room === 'BOSS' && !session.isBossDefeated) {
            setLastDiscoveryMessage("Hostile Boss signature detected. Squad is ready to engage. Commencing Direct Assault?");
        } else if (room === 'BOSS' && session.isBossDefeated) {
            setLastDiscoveryMessage("Enemy High-Value Target neutralized. Sector secured. We can extract safely from this point.");
        } else if (room === 'TRAP') {
            setLastDiscoveryMessage("WARNING: Trap triggered! Structural integrity compromised, but area is currently safe. What should we do next?");
        } else if (isEntranceNode && (lastDiscoveryMessage === '' || lastDiscoveryMessage.includes('Infiltration'))) {
            setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep. What's our first move?`);
        } else if (room === 'EMPTY') {
            const goldTerms = ['Looted', 'Found', 'Discovered', 'cache', 'coins', 'gold'];
            const foundGold = goldTerms.some(term => latestLog?.includes(term));

            if (foundGold) {
                setLastDiscoveryMessage("Treasury cache secured. This sector is now clear and safe. What should be our next course of action?");
            } else {
                setLastDiscoveryMessage("Scans indicate this area is vacant. No immediate threats detected. What is the next move?");
            }
        }
    }, [session.playerPos, session.grid, session.npcFound, dungeon.name, isEntranceNode, state.logs, session.isBossDefeated, hasTriggeredVictory]);

    useEffect(() => {
        if (!isReady || !containerRef.current) return;

        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO,
                parent: containerRef.current,
                width: containerRef.current.clientWidth,
                height: containerRef.current.clientHeight,
                backgroundColor: 'transparent',
                transparent: true,
                scene: [DungeonScene],
                scale: {
                    mode: Phaser.Scale.RESIZE,
                    autoCenter: Phaser.Scale.CENTER_BOTH
                }
            };

            const game = new Phaser.Game(config);
            gameRef.current = game;

            game.scene.start('DungeonScene', {
                session,
                moveEnergy: dungeon.moveEnergy,
                bossEnergy: dungeon.bossEnergy,
                onMove: (dx: number, dy: number) => {
                    actions.moveInManualDungeon(dx, dy);
                }
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon.moveEnergy, dungeon.bossEnergy]);

    useEffect(() => {
        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
                gameRef.current = null;
            }
        };
    }, []);

    const handleDpadMove = (dx: number, dy: number) => {
        if (showVictoryOverlay || showResultPopup || rescueStep === 'DIALOGUE') return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleClose = () => {
        if (showVictoryOverlay || showResultPopup) return;
        actions.toggleManualDungeonOverlay(false);
    };

    const handleAbort = () => {
        actions.retreatFromManualDungeon();
        setShowAbortConfirm(false);
    };

    const handleRetreatAtEntrance = () => {
        actions.retreatFromManualDungeon();
        setShowRetreatAtEntranceConfirm(false);
    };

    const handleRescueClick = () => {
        setRescueStep('DIALOGUE');
    };

    const handleRescueConfirm = () => {
        if (session.dungeonId === 'dungeon_t1_rats') {
            actions.rescueMercenary('tilly_footloose');
        }
        setRescueStep('DONE');
    };

    const navOptions = useMemo(() => {
        if (rescueStep === 'DIALOGUE') {
            return [
                { label: "Accept Escort Request", action: handleRescueConfirm, variant: 'primary' as const }
            ];
        }

        const baseOptions = [
            { 
                label: "North", 
                action: () => handleDpadMove(0, -1), 
                disabled: session.playerPos.y <= 0 
            },
            { 
                label: "South", 
                action: () => handleDpadMove(0, 1), 
                disabled: session.playerPos.y >= dungeon.gridHeight - 1 
            },
            { 
                label: "West", 
                action: () => handleDpadMove(-1, 0), 
                disabled: session.playerPos.x <= 0 
            },
            { 
                label: "East", 
                action: () => handleDpadMove(1, 0), 
                disabled: session.playerPos.x >= dungeon.gridWidth - 1 
            },
        ];

        // "Return to Forge" 또는 "Retreat" 옵션은 오직 입구와 보스방에서만 노출
        if (isEntranceNode) {
            if (session.isBossDefeated) {
                return [
                    { label: "Return to Forge", action: actions.finishManualAssault, variant: 'primary' as const },
                    ...baseOptions
                ];
            } else {
                // 클리어 전 입구 귀환 시 경고 메시지 포함 퇴각 옵션
                return [
                    { label: "Retreat to Forge", action: () => setShowRetreatAtEntranceConfirm(true), variant: 'neutral' as const },
                    ...baseOptions
                ];
            }
        }

        if (isBossNode && session.isBossDefeated) {
            return [
                { label: "Return to Forge", action: actions.finishManualAssault, variant: 'primary' as const },
                ...baseOptions
            ];
        }

        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') {
            return [
                { label: "Rescue Survivor", action: handleRescueClick, variant: 'primary' as const },
                ...baseOptions
            ];
        }

        return baseOptions;
    }, [session.playerPos, dungeon, isNPCNode, isBossNode, session.npcFound, rescueStep, session.isBossDefeated, actions, isEntranceNode]);

    const tacticalDialogue = useMemo(() => {
        if (session.isBossDefeated) {
            return "Mission status: CLEARED. Sector lockdown lifted. We can extract safely from the Boss chamber or return to the Sector Entrance for extraction.";
        }

        if (isEntranceNode) {
            return "Current coordinates: Sector Entrance. Extraction point is active. If we retreat now without defeating the Boss, we will lose all collected resources.";
        }

        if (rescueStep === 'DIALOGUE') {
            return "Oh! Thank the gods! I thought the rats would have me for sure. Please, lead the way out... I'll find my own way back once we're clear of this floor.";
        }

        if (isNPCNode && !session.npcFound) return "Warning: Unidentified life-sign detected in the immediate vicinity. Civilian presence confirmed. Escort protocols advised. What is the next move?";

        if (isTrapNode) {
            return "TACTICAL ALERT: Active hazard detected on current coordinates! Avoid sustained exposure. What is our next move?";
        }

        const isLowHp = party.some(m => m.currentHp < m.maxHp * 0.25);
        if (isLowHp) {
            return "MEDICAL EMERGENCY: Multiple units at critical HP. Sector secured but retreat is advised. What should we do?";
        }

        if (avgEnergy < 15) {
            return "FATIGUE CRITICAL: Squad performance degraded. Area clear but exhaustion is high. Should we extract or proceed?";
        }

        return lastDiscoveryMessage || "Scanning sector... Area clear. What's the next move?";
    }, [avgEnergy, session.hasKey, isNPCNode, session.npcFound, rescueStep, lastDiscoveryMessage, session.isBossLocked, party, isTrapNode, session.isBossDefeated, isEntranceNode]);

    const speakerName = useMemo(() => {
        if (session.isBossDefeated) return "Tactical AI";
