      <div className="relative w-full max-w-xl h-fit max-h-full min-h-[200px] min-w-[280px] bg-indigo-950/20 border-2 border-indigo-500/30 rounded-3xl shadow-[0_0_60px_rgba(55,48,163,0.2)] flex flex-col overflow-hidden animate-in zoom-in-95 duration-500">

