import React, { useState, useEffect } from 'react';
import { Save, Upload, X, Trash2, Clock, Coins, Calendar, ChevronRight } from 'lucide-react';
import { getSaveMetadataList, SaveMetadata, deleteSlot } from '../../utils/saveSystem';
import ConfirmationModal from './ConfirmationModal';

interface SaveLoadModalProps {
    isOpen: boolean;
    mode: 'SAVE' | 'LOAD';
    onClose: () => void;
    onAction: (slotIndex: number) => void;
}

const SaveLoadModal: React.FC<SaveLoadModalProps> = ({ isOpen, mode, onClose, onAction }) => {
    const [metaList, setMetaList] = useState<SaveMetadata[]>([]);
    const [deleteConfirm, setDeleteConfirm] = useState<{ isOpen: boolean, index: number | null }>({
        isOpen: false,
        index: null
    });

    useEffect(() => {
        if (isOpen) {
            setMetaList(getSaveMetadataList());
        }
    }, [isOpen]);

    if (!isOpen) return null;

    const slots = [0, 1, 2]; // 3개의 슬롯 지원

    const formatDate = (ts: number) => {
        return new Intl.DateTimeFormat('ko-KR', {
            month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
        }).format(new Date(ts));
    };

    const requestDelete = (e: React.MouseEvent, index: number) => {
        e.stopPropagation();
        setDeleteConfirm({ isOpen: true, index });
    };

    const handleConfirmDelete = () => {
        if (deleteConfirm.index !== null) {
            deleteSlot(deleteConfirm.index);
            setMetaList(getSaveMetadataList());
            setDeleteConfirm({ isOpen: false, index: null });
        }
    };

    const handleSlotClick = (index: number) => {
        onAction(index);
        if (mode === 'SAVE') {
            setTimeout(() => setMetaList(getSaveMetadataList()), 100);
        }
    };

    return (
        <>
            <div className="fixed inset-0 z-[1500] flex items-center justify-center bg-black/80 backdrop-blur-md px-[10%] py-[15%] overflow-hidden animate-in fade-in duration-200">
                <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-fit max-w-[450px] h-fit max-h-full min-h-[300px] min-w-[280px] shadow-[0_40px_80px_-20px_rgba(0,0,0,0.9)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 mx-auto">

                    {/* Header */}
                    <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="bg-stone-800 p-2 rounded-xl border border-stone-700 text-amber-500">
                                {mode === 'SAVE' ? <Save className="w-5 h-5" /> : <Upload className="w-5 h-5" />}
                            </div>
                            <h3 className="font-bold font-serif text-lg text-stone-200 tracking-wide uppercase">
                                {mode === 'SAVE' ? 'Save Game' : 'Load Game'}
                            </h3>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors ml-4">
                            <X className="w-5 h-5" />
                        </button>
                    </div>

                    {/* Slot List */}
                    <div className="p-4 space-y-3 overflow-y-auto flex-1 custom-scrollbar min-h-0">
                        {slots.map(index => {
                            const meta = metaList.find(m => m.index === index);
                            return (
                                <div 
                                    key={index}
                                    onClick={() => (meta || mode === 'SAVE') && handleSlotClick(index)}
                                    className={`group relative h-20 p-3 rounded-2xl border-2 transition-all flex flex-col justify-center gap-2 ${
                                        meta 
                                        ? 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750 cursor-pointer' 
                                        : mode === 'SAVE' 
                                            ? 'bg-stone-900 border-stone-800 border-dashed hover:border-stone-600 text-stone-600 cursor-pointer'
                                            : 'bg-stone-950 border-stone-900 text-stone-600 cursor-not-allowed opacity-60'
                                    }`}
                                >
                                    <div className="flex justify-between items-center w-full gap-4">
                                        <div className="flex items-center gap-2 min-w-0">
                                            <span className="font-black text-[10px] uppercase tracking-widest text-stone-500 group-hover:text-amber-500">Slot {index + 1}</span>
                                            {meta?.version && (
                                                <span className="px-1.5 py-0.5 bg-stone-950 rounded text-[7px] font-mono font-bold text-stone-600 border border-stone-800 group-hover:border-amber-900/50 group-hover:text-amber-700 transition-colors">
                                                    v{meta.version}
                                                </span>
                                            )}
                                        </div>
                                        {meta && (
                                            <div className="flex items-center gap-2 shrink-0">
                                                <div className="flex items-center gap-1 text-[9px] text-stone-500 font-mono">
                                                    <Clock className="w-2.5 h-2.5" /> {formatDate(meta.timestamp)}
                                                </div>
                                                <button onClick={(e) => requestDelete(e, index)} className="p-1 hover:text-red-500 transition-colors">
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {meta ? (
                                        <div className="flex items-center justify-between w-full gap-4">
                                            <div className="flex items-center gap-4">
                                                <div className="flex items-center gap-1.5">
                                                    <Calendar className="w-3.5 h-3.5 text-stone-500" />
                                                    <span className="text-xs md:text-sm font-bold text-stone-200">Day {meta.day}</span>
                                                </div>
                                                <div className="flex items-center gap-1.5">
                                                    <Coins className="w-3.5 h-3.5 text-amber-500" />
                                                    <span className="text-xs md:text-sm font-bold text-amber-400 font-mono">{meta.gold}G</span>
                                                </div>
                                            </div>
                                            <ChevronRight className="w-5 h-5 text-stone-600 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />
                                        </div>
                                    ) : (
                                        <div className="w-full py-0.5">
                                            <div className="text-center text-[10px] font-black uppercase tracking-[0.2em] italic opacity-70">
                                                {mode === 'SAVE' ? 'Click to Record Progress' : 'Empty Data Slot'}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>

                    <div className="p-3 bg-stone-950 text-center border-t border-stone-800 shrink-0">
                        <p className="text-[9px] md:text-[10px] text-stone-600 font-mono uppercase tracking-tighter">Your progress is kept in browser local storage.</p>
                    </div>
                </div>
            </div>

            <ConfirmationModal 
                isOpen={deleteConfirm.isOpen}
                title="Delete Save Data"
                message={`Are you sure you want to delete the data in Slot ${deleteConfirm.index !== null ? deleteConfirm.index + 1 : ''}? This action cannot be undone.`}
                confirmLabel="Delete Forever"
                onConfirm={handleConfirmDelete}
                onCancel={() => setDeleteConfirm({ isOpen: false, index: null })}
                isDanger={true}
            />
        </>
    );
};

export default SaveLoadModal;

import { GameState, ManualDungeonSession, RoomType } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    // 1. Entrance
    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    // 2. Boss
    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    // 3. Key (if locked)
    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    // 4. Hidden NPC (Tilly in Rat Cellar)
    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    // 5. Random Gold Piles & Traps
    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        goldCollected: 0
    };

    // Update participating mercenaries status to ON_EXPEDITION
    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tread carefully.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) return state;

    const targetRoom = session.grid[newY][newX];
    const isAlreadyVisited = session.visited[newY][newX];

    // 이미 밝혀진(방문한) 공간은 이동 비용이 -1임 (에너지가 1 회복됨)
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));

    // 에너지가 부족한지 체크 (회복될 때는 체크 통과)
    const canMove = cost < 0 || party.every(m => (m.expeditionEnergy || 0) >= cost);

    if (!canMove) {
        return {
            ...state,
            logs: [`Your squad is too exhausted to move.`, ...state.logs]
        };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return {
            ...state,
            logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs]
        };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            // 에너지는 최대 100까지 회복/소모
            let nextEnergy = Math.max(0, Math.min(100, (m.expeditionEnergy || 0) - cost));
            let nextHp = m.currentHp;

            // Trap Logic: -25 HP to everyone in the party
            if (targetRoom === 'TRAP' && !isAlreadyVisited) {
                nextHp = Math.max(0, m.currentHp - 25);
            }

            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    // Grid modification logic
    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let isBossDefeated = session.isBossDefeated;

    if (targetRoom === 'GOLD') {
        const tier = dungeon.tier || 1;
        const roll = Math.random();

        if (roll < 0.65) {
            extraGold = tier * 25;
            logMsg = `Looted a small pouch of gold! (+${extraGold} G)`;
        } else if (roll < 0.90) {
            extraGold = tier * 50;
            logMsg = `Found a stash of coins! (+${extraGold} G)`;
        } else {
            extraGold = tier * 75;
            logMsg = `Discovered an ancient gold cache! (+${extraGold} G)`;
        }

        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `IT'S A TRAP! The squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY') {
        logMsg = `Found a rusted key!`;
        newGrid[newY][newX] = 'EMPTY'; // 열쇠 획득 시 타일 비움
    } else if (targetRoom === 'NPC' && !session.npcFound) {
        logMsg = `Spotted a survivor hiding in the shadows!`;
    } else if (targetRoom === 'BOSS') {
        logMsg = `BOSS DEFEATED! Area secured.`;
        isBossDefeated = true;
    }

    const newSession: ManualDungeonSession = {
        ...session,
        grid: newGrid,
        playerPos: { x: newX, y: newY },
        visited: newVisited,
        hasKey: targetRoom === 'KEY' ? true : session.hasKey,
        isBossDefeated,
        goldCollected: session.goldCollected + extraGold
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: newSession,
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId,
            dungeonId: session.dungeonId,
            partyIds: session.partyIds,
            startTime: Date.now(),
            endTime: Date.now(),
            status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { 
        expeditionId: dummyExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    const totalManualGold = session.goldCollected;

    // Manual Dungeon Summary는 이미 보여줬으므로 전역 결과창은 띄우지 않음
    return { 
        ...finalState, 
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: {
                ...finalState.stats.dailyFinancials,
                incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold
            }
        },
        dungeonResult: null, // 결과창 팝업 방지
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            return { ...m, status: 'HIRED' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: ['The squad retreated from the area.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    if (state.knownMercenaries.some(m => m.id === payload.npcId)) return state;
    if (state.activeManualDungeon?.rescuedNpcId === payload.npcId) return state;

    // NPC 구출 시 현재 그리드에서 해당 NPC 아이콘 제거 (EMPTY로 변경)
    const currentSession = state.activeManualDungeon;
    let newGrid = currentSession ? [...currentSession.grid.map(row => [...row])] : null;
    if (newGrid && currentSession) {
        newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';
    }

    const newSession = currentSession ? {
        ...currentSession,
        grid: newGrid as RoomType[][],
        npcFound: true,
        rescuedNpcId: payload.npcId
    } : null;

    return {
        ...state,
        activeManualDungeon: newSession,
        logs: [`Rescue initiated for survivor. Secure the objective to escort them out.`, ...state.logs]
    };
};

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Trophy, Sparkles, Coins, ArrowRight, Package, ChevronUp, ChevronDown, CheckCircle, AlertTriangle, Shield
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl } from '../../../utils';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);
    const [showRetreatAtEntranceConfirm, setShowRetreatAtEntranceConfirm] = useState(false);

    // UI states
    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);

    // Victory sequence states
    const [showResultPopup, setShowResultPopup] = useState(false);
    const [hasTriggeredVictory, setHasTriggeredVictory] = useState(false);

    // Persistent tactical feedback
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');

    // Rescue interaction state
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    if (!session) return null;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return null;

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const avgEnergy = party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1);

    const currentRoomType = session.grid[session.playerPos.y][session.playerPos.x];
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';
    const isBossNode = currentRoomType === 'BOSS';
    const isTrapNode = currentRoomType === 'TRAP';

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) {
                setIsReady(true);
            } else {
                requestAnimationFrame(checkSize);
            }
        };
        checkSize();
    }, []);

    useEffect(() => {
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const latestLog = state.logs[0];

        if (session.isBossDefeated && !hasTriggeredVictory) {
            setShowResultPopup(true); // 보스 처치 즉시 통합 결과창 노출
            setHasTriggeredVictory(true);
            return;
        }

        if (room === 'KEY') setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location. What should we do next?");
        else if (room === 'NPC' && !session.npcFound) setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols. What is the next move?");
        else if (room === 'BOSS' && !session.isBossDefeated) setLastDiscoveryMessage("Hostile Boss signature detected. Squad is ready to engage. Commencing Direct Assault?");
        else if (room === 'BOSS' && session.isBossDefeated) setLastDiscoveryMessage("Enemy High-Value Target neutralized. Sector secured. We can extract safely from this point.");
        else if (room === 'TRAP') setLastDiscoveryMessage("WARNING: Trap triggered! Structural integrity compromised, but area is currently safe. What should we do next?");
        else if (isEntranceNode && (lastDiscoveryMessage === '' || lastDiscoveryMessage.includes('Infiltration'))) setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep. What's our first move?`);
        else if (room === 'EMPTY') {
            const goldTerms = ['Looted', 'Found', 'Discovered', 'cache', 'coins', 'gold'];
            if (goldTerms.some(term => latestLog?.includes(term))) setLastDiscoveryMessage("Treasury cache secured. This sector is now clear and safe. What should be our next course of action?");
            else setLastDiscoveryMessage("Scans indicate this area is vacant. No immediate threats detected. What is the next move?");
        }
    }, [session.playerPos, session.grid, session.npcFound, dungeon.name, isEntranceNode, state.logs, session.isBossDefeated, hasTriggeredVictory]);

    useEffect(() => {
        if (!isReady || !containerRef.current) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO,
                parent: containerRef.current,
                width: containerRef.current.clientWidth,
                height: containerRef.current.clientHeight,
                backgroundColor: 'transparent',
                transparent: true,
                scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', {
                session,
                moveEnergy: dungeon.moveEnergy,
                bossEnergy: dungeon.bossEnergy,
                onMove: (dx: number, dy: number) => { actions.moveInManualDungeon(dx, dy); }
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon.moveEnergy, dungeon.bossEnergy]);

    useEffect(() => { return () => { if (gameRef.current) { gameRef.current.destroy(true); gameRef.current = null; } }; }, []);

    const handleDpadMove = (dx: number, dy: number) => {
        if (showResultPopup || rescueStep === 'DIALOGUE') return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleClose = () => { if (showResultPopup) return; actions.toggleManualDungeonOverlay(false); };
    const handleAbort = () => { actions.retreatFromManualDungeon(); setShowAbortConfirm(false); };
    const handleRetreatAtEntrance = () => { actions.retreatFromManualDungeon(); setShowRetreatAtEntranceConfirm(false); };
    const handleRescueClick = () => { setRescueStep('DIALOGUE'); };
    const handleRescueConfirm = () => { if (session.dungeonId === 'dungeon_t1_rats') actions.rescueMercenary('tilly_footloose'); setRescueStep('DONE'); };
    const handleClaimRewardsAndExit = () => { actions.finishManualAssault(); };

    const navOptions = useMemo(() => {
        if (rescueStep === 'DIALOGUE') return [{ label: "Accept Escort Request", action: handleRescueConfirm, variant: 'primary' as const }];
        const baseOptions = [
            { label: "North", action: () => handleDpadMove(0, -1), disabled: session.playerPos.y <= 0 },
            { label: "South", action: () => handleDpadMove(0, 1), disabled: session.playerPos.y >= dungeon.gridHeight - 1 },
            { label: "West", action: () => handleDpadMove(-1, 0), disabled: session.playerPos.x <= 0 },
            { label: "East", action: () => handleDpadMove(1, 0), disabled: session.playerPos.x >= dungeon.gridWidth - 1 },
        ];
        if (session.isBossDefeated && (isEntranceNode || isBossNode)) return [{ label: "Claim Rewards & Return", action: () => setShowResultPopup(true), variant: 'primary' as const }, ...baseOptions];
        if (isEntranceNode && !session.isBossDefeated) return [{ label: "Retreat to Forge", action: () => setShowRetreatAtEntranceConfirm(true), variant: 'neutral' as const }, ...baseOptions];
        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') return [{ label: "Rescue Survivor", action: handleRescueClick, variant: 'primary' as const }, ...baseOptions];
        return baseOptions;
    }, [session.playerPos, dungeon, isNPCNode, isBossNode, session.npcFound, rescueStep, session.isBossDefeated, actions, isEntranceNode]);

    const speakerName = useMemo(() => {
        if (session.isBossDefeated) return "Tactical AI";
        if (rescueStep === 'DIALOGUE') return "Tilly Footloose";
        return "Tactical Link";
    }, [session.isBossDefeated, rescueStep]);

    const tacticalDialogue = useMemo(() => {
        if (session.isBossDefeated) return "Mission status: CLEARED. Sector lockdown lifted. We can extract safely from the Boss chamber or the Sector Entrance. Would you like to secure the rewards now?";
        if (isEntranceNode) return "Current coordinates: Sector Entrance. Extraction point is active. If we retreat now without defeating the Boss, we will lose all collected resources.";
        if (rescueStep === 'DIALOGUE') return "Oh! Thank the gods! I thought the rats would have me for sure. Please, lead the way out... I'll find my own way back once we're clear of this floor.";
        if (isNPCNode && !session.npcFound) return "Warning: Unidentified life-sign detected in the immediate vicinity. Civilian presence confirmed. Escort protocols advised. What is the next move?";
        if (isTrapNode) return "TACTICAL ALERT: Active hazard detected on current coordinates! Avoid sustained exposure. What is our next move?";
        return lastDiscoveryMessage || "Scanning sector... Area clear. What's the next move?";
    }, [session.isBossDefeated, isEntranceNode, rescueStep, isNPCNode, session.npcFound, isTrapNode, lastDiscoveryMessage]);

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className="absolute inset-0 z-0" />
            <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2 mb-1 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors group">
                    <div className="flex items-center gap-2"><Shield className="w-3.5 h-3.5 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                    {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" />}
                </button>
                {isSquadStatusExpanded && party.map(merc => {
                    const hpPer = (merc.currentHp / merc.maxHp) * 100;
                    return (
                        <div key={merc.id} className="bg-stone-900/80 border border-stone-700/50 p-2 rounded-xl backdrop-blur-md shadow-lg animate-in slide-in-from-top-2 duration-300">
                            <div className="flex items-center gap-2 mb-1.5"><div className="w-6 h-6 rounded-full bg-stone-800 flex items-center justify-center border border-white/5 text-xs shadow-inner shrink-0">{merc.icon}</div><div className="min-w-0 flex-1"><div className="text-[10px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div><div className="text-[7px] text-stone-500 font-bold uppercase tracking-tighter truncate">{merc.job} • LV.{merc.level}</div></div></div>
                            <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter mb-0.5"><span>HP</span><span>{Math.floor(merc.currentHp)}/{merc.maxHp}</span></div>
                            <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                        </div>
                    );
                })}
            </div>
            {rescueStep === 'DIALOGUE' && (
                <div className="absolute inset-0 z-30 flex flex-col items-center justify-end pointer-events-none pb-0 animate-in fade-in zoom-in-95 duration-700">
                    <div className="relative h-[65dvh] md:h-[85dvh] flex justify-center bottom-[20dvh] md:bottom-[10dvh]"><img src={getAssetUrl('tily_footloose.png')} alt="Rescued Survivor" className="h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_50px_rgba(0,0,0,1)]" /></div>
                </div>
            )}
            <div className="relative p-2 md:p-4 bg-stone-950/20 backdrop-blur-md border-b border-white/10 flex justify-between items-center shrink-0 z-50 gap-2">
                <div className="flex items-center gap-2 md:gap-4 min-w-0"><div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl border flex items-center justify-center shrink-0 transition-all ${session.hasKey ? 'bg-amber-900/40 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.4)] animate-pulse' : 'bg-stone-950/50 border-stone-800'}`}><Key className={`w-5 h-5 md:w-7 md:h-7 ${session.hasKey ? 'text-amber-400' : 'text-stone-600'}`} /></div><div className="min-w-0"><h2 className="text-stone-100 font-black uppercase text-xs md:text-lg leading-none drop-shadow-md truncate">{dungeon.name}</h2><div className="flex items-center gap-2 mt-1"><div className="flex items-center gap-1 bg-stone-950/60 px-1.5 py-0.5 rounded border border-white/5 shrink-0"><Zap className="w-2.5 h-2.5 text-blue-500" /><span className="text-[8px] md:text-[10px] font-mono font-bold text-blue-400 uppercase tracking-tighter">{Math.floor(avgEnergy)}%</span></div>{session.goldCollected > 0 && <div className="flex items-center gap-1 bg-amber-900/40 px-1.5 py-0.5 rounded border border-amber-600/30 shrink-0"><Coins className="w-2.5 h-2.5 text-amber-400" /><span className="text-[8px] md:text-[10px] font-mono font-bold text-amber-200 uppercase tracking-tighter">+{session.goldCollected}</span></div>}</div></div></div>
                <div className="flex items-center gap-1 md:gap-2 shrink-0"><button onClick={() => !session.isBossDefeated && setShowAbortConfirm(true)} disabled={session.isBossDefeated} className={`flex items-center gap-1 md:gap-2 px-2 md:px-3 py-1.5 md:py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/50 rounded-lg text-red-400 font-bold text-[9px] md:text-[10px] transition-all backdrop-blur-md ${session.isBossDefeated ? 'opacity-30 cursor-not-allowed' : ''}`}><LogOut className="w-3 h-3 md:w-3.5 md:h-3.5" /> <span className="hidden xs:inline">Abort</span></button><button onClick={handleClose} disabled={showResultPopup} className={`flex items-center gap-1 md:gap-2 px-2 md:px-4 py-1.5 md:py-2 bg-stone-800/60 hover:bg-stone-700/80 border border-white/10 rounded-lg text-stone-200 font-bold text-[9px] md:text-xs transition-all backdrop-blur-md ${showResultPopup ? 'opacity-30 cursor-not-allowed' : ''}`}><X className="w-3 h-3 md:w-4 md:h-4" /> <span>Pause</span></button></div>
            </div>
            <div className="flex-1 pointer-events-none" />
            <div className="relative z-40"><DialogueBox speaker={speakerName} text={tacticalDialogue} options={showResultPopup ? [] : (navOptions as any)} /></div>
            <ConfirmationModal isOpen={showAbortConfirm} title="Abandon Assault?" message="Retreating via system override will forfeit all progress in this floor. All spent energy will not be recovered." confirmLabel="Confirm Retreat" cancelLabel="Stay Focused" isDanger={true} onConfirm={handleAbort} onCancel={() => setShowAbortConfirm(false)} />
            <ConfirmationModal isOpen={showRetreatAtEntranceConfirm} title="Retreat to Forge?" message="If you leave the dungeon now without defeating the Boss, you will forfeit all loot and gold collected during this session. Do you wish to proceed?" confirmLabel="Confirm Retreat" cancelLabel="Continue Mission" isDanger={true} onConfirm={handleRetreatAtEntrance} onCancel={() => setShowRetreatAtEntranceConfirm(false)} />

            {showResultPopup && (
                <div className="fixed inset-0 z-[700] bg-black/90 backdrop-blur-md flex items-center justify-center px-[10%] py-[15%] animate-in fade-in duration-500 pointer-events-auto overflow-hidden">
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-3xl w-fit max-w-[600px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-[0_0_80px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-500 mx-auto">
                        <div className="bg-amber-600 p-4 md:p-6 flex flex-col items-center text-center text-white shrink-0">
                            <Trophy className="w-8 h-8 md:w-12 md:h-12 mb-1 md:mb-2 animate-bounce" />
                            <h2 className="text-xl md:text-2xl font-black italic tracking-tighter uppercase font-serif leading-none px-4">Objective Complete!</h2>
                            <p className="text-amber-100 text-[8px] md:text-[10px] font-black uppercase tracking-widest mt-1 px-6">Mission Summary</p>
                        </div>
                        <div className="p-4 md:p-6 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                            <div className="space-y-2">
                                <h3 className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest text-center">Treasury Secured</h3>
                                <div className="bg-stone-950 p-3 md:p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-1">
                                    <div className="flex items-center gap-2 text-stone-400 font-mono text-xs md:text-sm"><span>Base: {dungeon.goldReward}G</span><span>+</span><span className="text-amber-400">Bonus: {session.goldCollected}G</span></div>
                                    <div className="flex items-center gap-2 mt-1"><Coins className="w-5 h-5 md:w-6 md:h-6 text-amber-500" /><span className="text-xl md:text-3xl font-black font-mono text-stone-100">{dungeon.goldReward! + session.goldCollected} G</span></div>
                                </div>
                            </div>
                            <div className="space-y-2">
                                <h3 className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest text-center">Yield Projection</h3>
                                <div className="flex flex-wrap gap-2 justify-center">{dungeon.rewards.map((r, i) => (<div key={i} className="w-8 h-8 md:w-10 md:h-10 bg-stone-850 border border-stone-800 rounded-lg flex items-center justify-center p-1"><img src={getAssetUrl(`${r.itemId}.png`)} className="w-full h-full object-contain" /></div>))}{session.rescuedNpcId && <div className="w-8 h-8 md:w-10 md:h-10 bg-amber-900/30 border border-amber-600 rounded-lg flex items-center justify-center"><Sparkles className="w-5 h-5 md:w-6 md:h-6 text-amber-500" /></div>}</div>
                            </div>
                        </div>
                        <div className="p-4 md:p-6 pt-0 flex flex-col gap-2 md:gap-3 shrink-0">
                            <button onClick={handleClaimRewardsAndExit} className="w-full py-3 md:py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 border-b-4 border-emerald-800 text-[10px] md:text-base uppercase tracking-widest px-8"><Package className="w-4 h-4 md:w-5 md:h-5" />SECURE LOOT & RETURN</button>
                            <button onClick={() => setShowResultPopup(false)} className="w-full py-2.5 md:py-4 bg-stone-800 hover:bg-stone-700 text-stone-300 font-black rounded-xl transition-all flex items-center justify-center gap-2 text-[10px] md:text-sm uppercase tracking-widest px-6"><ArrowRight className="w-4 h-4 md:w-5 md:h-5" />KEEP EXPLORING</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AssaultNavigator;

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Trophy, Sparkles, Coins, ArrowRight, Package, ChevronUp, ChevronDown, CheckCircle, AlertTriangle, Shield, ChevronLeft, ChevronRight
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl } from '../../../utils';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);
    const [showRetreatAtEntranceConfirm, setShowRetreatAtEntranceConfirm] = useState(false);

    // UI states
    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);

    // Victory sequence states
    const [showResultPopup, setShowResultPopup] = useState(false);
    const [hasTriggeredVictory, setHasTriggeredVictory] = useState(false);

    // Persistent tactical feedback
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');

    // Rescue interaction state
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    if (!session) return null;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return null;

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const avgEnergy = party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1);

    const currentRoomType = session.grid[session.playerPos.y][session.playerPos.x];
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';
    const isBossNode = currentRoomType === 'BOSS';
    const isTrapNode = currentRoomType === 'TRAP';

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) {
                setIsReady(true);
            } else {
                requestAnimationFrame(checkSize);
            }
        };
        checkSize();
    }, []);

    useEffect(() => {
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const latestLog = state.logs[0];

        if (session.isBossDefeated && !hasTriggeredVictory) {
            setShowResultPopup(true); // 보스 처치 즉시 통합 결과창 노출
            setHasTriggeredVictory(true);
            return;
        }

        if (room === 'KEY') setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location. What should we do next?");
        else if (room === 'NPC' && !session.npcFound) setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols. What is the next move?");
        else if (room === 'BOSS' && !session.isBossDefeated) setLastDiscoveryMessage("Hostile Boss signature detected. Squad is ready to engage. Commencing Direct Assault?");
        else if (room === 'BOSS' && session.isBossDefeated) setLastDiscoveryMessage("Enemy High-Value Target neutralized. Sector secured. We can extract safely from this point.");
        else if (room === 'TRAP') setLastDiscoveryMessage("WARNING: Trap triggered! Structural integrity compromised, but area is currently safe. What should we do next?");
        else if (isEntranceNode && (lastDiscoveryMessage === '' || lastDiscoveryMessage.includes('Infiltration'))) setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep. What's our first move?`);
        else if (room === 'EMPTY') {
            const goldTerms = ['Looted', 'Found', 'Discovered', 'cache', 'coins', 'gold'];
            if (goldTerms.some(term => latestLog?.includes(term))) setLastDiscoveryMessage("Treasury cache secured. This sector is now clear and safe. What should be our next course of action?");
            else setLastDiscoveryMessage("Scans indicate this area is vacant. No immediate threats detected. What is the next move?");
        }
    }, [session.playerPos, session.grid, session.npcFound, dungeon.name, isEntranceNode, state.logs, session.isBossDefeated, hasTriggeredVictory]);

    useEffect(() => {
        if (!isReady || !containerRef.current) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO,
                parent: containerRef.current,
                width: containerRef.current.clientWidth,
                height: containerRef.current.clientHeight,
                backgroundColor: 'transparent',
                transparent: true,
                scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', {
                session,
                moveEnergy: dungeon.moveEnergy,
                bossEnergy: dungeon.bossEnergy,
                onMove: (dx: number, dy: number) => { actions.moveInManualDungeon(dx, dy); }
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon.moveEnergy, dungeon.bossEnergy]);

    useEffect(() => { return () => { if (gameRef.current) { gameRef.current.destroy(true); gameRef.current = null; } }; }, []);

    const handleDpadMove = (dx: number, dy: number) => {
        if (showResultPopup || rescueStep === 'DIALOGUE') return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleClose = () => { if (showResultPopup) return; actions.toggleManualDungeonOverlay(false); };
    const handleAbort = () => { actions.retreatFromManualDungeon(); setShowAbortConfirm(false); };
    const handleRetreatAtEntrance = () => { actions.retreatFromManualDungeon(); setShowRetreatAtEntranceConfirm(false); };
    const handleRescueClick = () => { setRescueStep('DIALOGUE'); };
    const handleRescueConfirm = () => { if (session.dungeonId === 'dungeon_t1_rats') actions.rescueMercenary('tilly_footloose'); setRescueStep('DONE'); };
    const handleClaimRewardsAndExit = () => { actions.finishManualAssault(); };

    // Interaction options only (No Movement)
    const interactionOptions = useMemo(() => {
        if (rescueStep === 'DIALOGUE') return [{ label: "Accept Escort Request", action: handleRescueConfirm, variant: 'primary' as const }];
        const opts = [];
        if (session.isBossDefeated && (isEntranceNode || isBossNode)) opts.push({ label: "Claim Rewards & Return", action: () => setShowResultPopup(true), variant: 'primary' as const });
        if (isEntranceNode && !session.isBossDefeated) opts.push({ label: "Retreat to Forge", action: () => setShowRetreatAtEntranceConfirm(true), variant: 'neutral' as const });
        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') opts.push({ label: "Rescue Survivor", action: handleRescueClick, variant: 'primary' as const });
        return opts;
    }, [session.playerPos, dungeon, isNPCNode, isBossNode, session.npcFound, rescueStep, session.isBossDefeated, actions, isEntranceNode]);

    const speakerName = useMemo(() => {
        if (session.isBossDefeated) return "Tactical AI";
        if (rescueStep === 'DIALOGUE') return "Tilly Footloose";
        return "Tactical Link";
    }, [session.isBossDefeated, rescueStep]);

    const tacticalDialogue = useMemo(() => {
        if (session.isBossDefeated) return "Mission status: CLEARED. Sector lockdown lifted. We can extract safely from the Boss chamber or the Sector Entrance. Would you like to secure the rewards now?";
        if (isEntranceNode) return "Current coordinates: Sector Entrance. Extraction point is active. If we retreat now without defeating the Boss, we will lose all collected resources.";
        if (rescueStep === 'DIALOGUE') return "Oh! Thank the gods! I thought the rats would have me for sure. Please, lead the way out... I'll find my own way back once we're clear of this floor.";
        if (isNPCNode && !session.npcFound) return "Warning: Unidentified life-sign detected in the immediate vicinity. Civilian presence confirmed. Escort protocols advised. What is the next move?";
        if (isTrapNode) return "TACTICAL ALERT: Active hazard detected on current coordinates! Avoid sustained exposure. What is our next move?";
        return lastDiscoveryMessage || "Scanning sector... Area clear. What's the next move?";
    }, [session.isBossDefeated, isEntranceNode, rescueStep, isNPCNode, session.npcFound, isTrapNode, lastDiscoveryMessage]);

    const NavButton = ({ direction, dx, dy, disabled, Icon }: { direction: string, dx: number, dy: number, disabled: boolean, Icon: any }) => (
        <button 
            onClick={() => !disabled && handleDpadMove(dx, dy)}
            disabled={disabled}
            className={`w-12 h-12 md:w-16 md:h-16 flex items-center justify-center rounded-xl border-2 transition-all active:scale-90 shadow-2xl ${
                disabled 
                ? 'bg-stone-900/40 border-stone-800 text-stone-700 opacity-30 cursor-not-allowed' 
                : 'bg-stone-800/80 hover:bg-stone-700 border-stone-600 text-stone-200 backdrop-blur-md'
            }`}
            title={direction}
        >
            <Icon className="w-6 h-6 md:w-8 md:h-8" />
        </button>
    );

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className="absolute inset-0 z-0" />

            {/* Squad Status HUD */}
            <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2 mb-1 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors group">
                    <div className="flex items-center gap-2"><Shield className="w-3.5 h-3.5 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                    {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" />}
                </button>
                {isSquadStatusExpanded && party.map(merc => {
                    const hpPer = (merc.currentHp / merc.maxHp) * 100;
                    return (
                        <div key={merc.id} className="bg-stone-900/80 border border-stone-700/50 p-2 rounded-xl backdrop-blur-md shadow-lg animate-in slide-in-from-top-2 duration-300">
                            <div className="flex items-center gap-2 mb-1.5"><div className="w-6 h-6 rounded-full bg-stone-800 flex items-center justify-center border border-white/5 text-xs shadow-inner shrink-0">{merc.icon}</div><div className="min-w-0 flex-1"><div className="text-[10px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div><div className="text-[7px] text-stone-500 font-bold uppercase tracking-tighter truncate">{merc.job} • LV.{merc.level}</div></div></div>
                            <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter mb-0.5"><span>HP</span><span>{Math.floor(merc.currentHp)}/{merc.maxHp}</span></div>
                            <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                        </div>
                    );
                })}
            </div>

            {/* Character Sprite Overlay */}
            {rescueStep === 'DIALOGUE' && (
                <div className="absolute inset-0 z-30 flex flex-col items-center justify-end pointer-events-none pb-0 animate-in fade-in zoom-in-95 duration-700">
                    <div className="relative h-[65dvh] md:h-[85dvh] flex justify-center bottom-[20dvh] md:bottom-[10dvh]"><img src={getAssetUrl('tily_footloose.png')} alt="Rescued Survivor" className="h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_50px_rgba(0,0,0,1)]" /></div>
                </div>
            )}

            {/* Top Info Bar */}
            <div className="relative p-2 md:p-4 bg-stone-950/20 backdrop-blur-md border-b border-white/10 flex justify-between items-center shrink-0 z-50 gap-2">
                <div className="flex items-center gap-2 md:gap-4 min-w-0"><div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl border flex items-center justify-center shrink-0 transition-all ${session.hasKey ? 'bg-amber-900/40 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.4)] animate-pulse' : 'bg-stone-950/50 border-stone-800'}`}><Key className={`w-5 h-5 md:w-7 md:h-7 ${session.hasKey ? 'text-amber-400' : 'text-stone-600'}`} /></div><div className="min-w-0"><h2 className="text-stone-100 font-black uppercase text-xs md:text-lg leading-none drop-shadow-md truncate">{dungeon.name}</h2><div className="flex items-center gap-2 mt-1"><div className="flex items-center gap-1 bg-stone-950/60 px-1.5 py-0.5 rounded border border-white/5 shrink-0"><Zap className="w-2.5 h-2.5 text-blue-500" /><span className="text-[8px] md:text-[10px] font-mono font-bold text-blue-400 uppercase tracking-tighter">{Math.floor(avgEnergy)}%</span></div>{session.goldCollected > 0 && <div className="flex items-center gap-1 bg-amber-900/40 px-1.5 py-0.5 rounded border border-amber-600/30 shrink-0"><Coins className="w-2.5 h-2.5 text-amber-400" /><span className="text-[8px] md:text-[10px] font-mono font-bold text-amber-200 uppercase tracking-tighter">+{session.goldCollected}</span></div>}</div></div></div>
                <div className="flex items-center gap-1 md:gap-2 shrink-0"><button onClick={() => !session.isBossDefeated && setShowAbortConfirm(true)} disabled={session.isBossDefeated} className={`flex items-center gap-1 md:gap-2 px-2 md:px-3 py-1.5 md:py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/50 rounded-lg text-red-400 font-bold text-[9px] md:text-[10px] transition-all backdrop-blur-md ${session.isBossDefeated ? 'opacity-30 cursor-not-allowed' : ''}`}><LogOut className="w-3 h-3 md:w-3.5 md:h-3.5" /> <span className="hidden xs:inline">Abort</span></button><button onClick={handleClose} disabled={showResultPopup} className={`flex items-center gap-1 md:gap-2 px-2 md:px-4 py-1.5 md:py-2 bg-stone-800/60 hover:bg-stone-700/80 border border-white/10 rounded-lg text-stone-200 font-bold text-[9px] md:text-xs transition-all backdrop-blur-md ${showResultPopup ? 'opacity-30 cursor-not-allowed' : ''}`}><X className="w-3 h-3 md:w-4 md:h-4" /> <span>Pause</span></button></div>
            </div>

            {/* Bottom Interaction Unit: D-Pad + Dialogue */}
            <div className="absolute bottom-0 left-0 right-0 z-40 px-[2%] pb-[2%] flex flex-col items-center pointer-events-none">

                {/* D-Pad Navigation (Above Dialogue) */}
                <div className={`mb-4 transition-all duration-500 pointer-events-auto ${showResultPopup || rescueStep === 'DIALOGUE' ? 'opacity-0 scale-90 translate-y-4 pointer-events-none' : 'opacity-100 scale-100 translate-y-0'}`}>
                    <div className="grid grid-cols-3 gap-1 md:gap-3 p-2 bg-stone-900/40 backdrop-blur-md rounded-[2rem] border border-white/5 shadow-2xl shadow-black/50">
                        <div />
                        <NavButton direction="North" dx={0} dy={-1} disabled={session.playerPos.y <= 0} Icon={ChevronUp} />
                        <div />

                        <NavButton direction="West" dx={-1} dy={0} disabled={session.playerPos.x <= 0} Icon={ChevronLeft} />
                        <div className="w-12 h-12 md:w-16 md:h-16 flex items-center justify-center">
                            <div className="w-3 h-3 md:w-4 md:h-4 bg-amber-500/20 rounded-full animate-pulse border border-amber-500/30 shadow-[0_0_15px_rgba(245,158,11,0.2)]" />
                        </div>
                        <NavButton direction="East" dx={1} dy={0} disabled={session.playerPos.x >= dungeon.gridWidth - 1} Icon={ChevronRight} />

                        <div />
                        <NavButton direction="South" dx={0} dy={1} disabled={session.playerPos.y >= dungeon.gridHeight - 1} Icon={ChevronDown} />
                        <div />
                    </div>
                </div>

                {/* Interaction Dialogue Box */}
                <div className="w-full pointer-events-auto">
                    <DialogueBox 
                        speaker={speakerName} 
                        text={tacticalDialogue} 
                        options={showResultPopup ? [] : (interactionOptions as any)} 
                    />
                </div>
            </div>

            {/* Modals */}
            <ConfirmationModal isOpen={showAbortConfirm} title="Abandon Assault?" message="Retreating via system override will forfeit all progress in this floor. All spent energy will not be recovered." confirmLabel="Confirm Retreat" cancelLabel="Stay Focused" isDanger={true} onConfirm={handleAbort} onCancel={() => setShowAbortConfirm(false)} />
            <ConfirmationModal isOpen={showRetreatAtEntranceConfirm} title="Retreat to Forge?" message="If you leave the dungeon now without defeating the Boss, you will forfeit all loot and gold collected during this session. Do you wish to proceed?" confirmLabel="Confirm Retreat" cancelLabel="Continue Mission" isDanger={true} onConfirm={handleRetreatAtEntrance} onCancel={() => setShowRetreatAtEntranceConfirm(false)} />

            {showResultPopup && (
                <div className="fixed inset-0 z-[700] bg-black/90 backdrop-blur-md flex items-center justify-center px-[10%] py-[15%] animate-in fade-in duration-500 pointer-events-auto overflow-hidden">
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-3xl w-fit max-w-[600px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-[0_0_80px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-500 mx-auto">
                        <div className="bg-amber-600 p-4 md:p-6 flex flex-col items-center text-center text-white shrink-0">
                            <Trophy className="w-8 h-8 md:w-12 md:h-12 mb-1 md:mb-2 animate-bounce" />
                            <h2 className="text-xl md:text-2xl font-black italic tracking-tighter uppercase font-serif leading-none px-4">Objective Complete!</h2>
                            <p className="text-amber-100 text-[8px] md:text-[10px] font-black uppercase tracking-widest mt-1 px-6">Mission Summary</p>
                        </div>
                        <div className="p-4 md:p-6 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                            <div className="space-y-2">
                                <h3 className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest text-center">Treasury Secured</h3>
                                <div className="bg-stone-950 p-3 md:p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-1">
                                    <div className="flex items-center gap-2 text-stone-400 font-mono text-xs md:text-sm"><span>Base: {dungeon.goldReward}G</span><span>+</span><span className="text-amber-400">Bonus: {session.goldCollected}G</span></div>
                                    <div className="flex items-center gap-2 mt-1"><Coins className="w-5 h-5 md:w-6 md:h-6 text-amber-500" /><span className="text-xl md:text-3xl font-black font-mono text-stone-100">{dungeon.goldReward! + session.goldCollected} G</span></div>
                                </div>
                            </div>
                            <div className="space-y-2">
                                <h3 className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest text-center">Yield Projection</h3>
                                <div className="flex flex-wrap gap-2 justify-center">{dungeon.rewards.map((r, i) => (<div key={i} className="w-8 h-8 md:w-10 md:h-10 bg-stone-850 border border-stone-800 rounded-lg flex items-center justify-center p-1"><img src={getAssetUrl(`${r.itemId}.png`)} className="w-full h-full object-contain" /></div>))}{session.rescuedNpcId && <div className="w-8 h-8 md:w-10 md:h-10 bg-amber-900/30 border border-amber-600 rounded-lg flex items-center justify-center"><Sparkles className="w-5 h-5 md:w-6 md:h-6 text-amber-500" /></div>}</div>
                            </div>
                        </div>
                        <div className="p-4 md:p-6 pt-0 flex flex-col gap-2 md:gap-3 shrink-0">
                            <button onClick={handleClaimRewardsAndExit} className="w-full py-3 md:py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 border-b-4 border-emerald-800 text-[10px] md:text-base uppercase tracking-widest px-8"><Package className="w-4 h-4 md:w-5 md:h-5" />SECURE LOOT & RETURN</button>
                            <button onClick={() => setShowResultPopup(false)} className="w-full py-2.5 md:py-4 bg-stone-800 hover:bg-stone-700 text-stone-300 font-black rounded-xl transition-all flex items-center justify-center gap-2 text-[10px] md:text-sm uppercase tracking-widest px-6"><ArrowRight className="w-4 h-4 md:w-5 md:h-5" />KEEP EXPLORING</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

